        XCTAssertTrue(contract.validationAnchors.contains("GH-461-OMS-ENGINE-CLIENT-PORTFOLIO-BOUNDARY"))
        XCTAssertTrue(contract.validationAnchors.contains("GH-461-ROLLBACK-INCIDENT-EVIDENCE"))

