    func testGH462OMSLocalOrderTransitionEvidenceRejectsIllegalTransitionAndRuntimeBypass() throws {
        XCTAssertThrowsError(
            try L4OMSLocalOrderTransitionEvidenceBuilder(
                productionRuntimeEnabled: true
            )
        ) { error in
