        XCTAssertTrue(adapterSource.contains("ReleaseV040BinanceDryRunExecutionClientRedactedRequest"))
        XCTAssertFalse(adapterSource.contains("URLSession"))
        XCTAssertFalse(adapterSource.contains("URLRequest"))

