        XCTAssertTrue(packageSource.contains("\"Database/ReleaseV090TestnetReadOnlyMonitorSessionStore.swift\""))
        XCTAssertTrue(runScript.contains("bash checks/verify-v0.9.0-monitor-session-store.sh"))
