        XCTAssertEqual(evidence.nextProfile.rules.allowedProductTypes.map(\.rawValue), ["spot", "usdsPerpetual"])
        XCTAssertEqual(evidence.deterministicDiff.changedFields, [
            "profileVersion",
            "maxNotionalMinorUnits",
            "maxExposureMinorUnits",
