    func testGH914ProductionReadinessArtifactStoreUsesLocalExplicitStates() throws {
        XCTAssertEqual(ProductionReadinessArtifactStoreAnchors.validationAnchors, [
            "GH-914-VERIFY-V0110-PRODUCTION-READINESS-ARTIFACT-STORE",
            "TVM-RELEASE-V0110-PRODUCTION-READINESS-ARTIFACT-STORE",
            "V0110-002-PRODUCTION-READINESS-ARTIFACT-STORE",
            "V0110-002-LOCAL-EVIDENCE-ROOT",
            "V0110-002-ARTIFACT-STATES",
            "V0110-002-READ-WRITE-PRIMITIVES",
            "V0110-002-NO-PRODUCTION-SECRET-ENDPOINT-ORDER"
        ])

        let evidenceRoot = FileManager.default.temporaryDirectory.appendingPathComponent(
            "MTPRO-GH914-ReadinessArtifactStore-\(UUID().uuidString)",
            isDirectory: true
        )
        addTeardownBlock {
            try? FileManager.default.removeItem(at: evidenceRoot)
        }

        let store = try ProductionReadinessArtifactStore(evidenceRootURL: evidenceRoot)
        let descriptor = try ProductionReadinessArtifactDescriptor(
            artifactID: Identifier.constant("gh-914-readiness-overview"),
            relativePath: "readiness/production-readiness-overview.json",
            artifactType: .jsonEvidence,
            staleAfterSeconds: 60
        )
        let now = Date(timeIntervalSince1970: 1_800_000_000)

        let missing = try store.inspectArtifact(descriptor, now: now)
        XCTAssertEqual(missing.state, .missing)
        XCTAssertEqual(missing.byteCount, 0)
        XCTAssertTrue(missing.recordHeld)
        XCTAssertTrue(missing.productionCapabilitiesDisabled)

        XCTAssertThrowsError(
            try ProductionReadinessArtifactDescriptor(
                artifactID: Identifier.constant("gh-914-path-escape"),
                relativePath: "../outside.json",
                artifactType: .jsonEvidence
            )
        )

        let invalidURL = try store.artifactURL(for: descriptor)
        try FileManager.default.createDirectory(
            at: invalidURL.deletingLastPathComponent(),
            withIntermediateDirectories: true
        )
        try Data("not-json".utf8).write(to: invalidURL, options: .atomic)
        let invalid = try store.inspectArtifact(descriptor, now: now)
        XCTAssertEqual(invalid.state, .invalid)
        XCTAssertEqual(invalid.stateReason, "invalid JSON evidence")
        XCTAssertTrue(invalid.recordHeld)
        try FileManager.default.removeItem(at: invalidURL)

        let payload = """
        {
          "artifactID": "gh-914-readiness-overview",
          "releaseVersion": "v0.11.0",
          "redactionProof": true,
          "noSecretValue": true,
          "noOrderPayload": true,
          "productionTradingEnabledByDefault": false,
          "productionCutoverAuthorized": false,
          "productionSecretRead": false,
          "productionEndpointConnected": false,
          "brokerEndpointConnected": false,
          "productionOrderSubmitted": false,
          "testnetOrderSubmissionAllowed": false
        }
        """
        let valid = try store.writeStringArtifact(
            descriptor: descriptor,
            string: payload,
            modifiedAt: now
        )
        XCTAssertEqual(valid.state, .valid)
        XCTAssertGreaterThan(valid.byteCount, 0)
        XCTAssertTrue(valid.absolutePath.hasPrefix(evidenceRoot.path))
        XCTAssertTrue(valid.recordHeld)
        XCTAssertTrue(valid.productionCapabilitiesDisabled)

        let read = try store.readArtifact(descriptor: descriptor, now: now)
        XCTAssertTrue(read.readHeld)
        XCTAssertEqual(String(decoding: read.data, as: UTF8.self), payload)

        let stale = try store.inspectArtifact(
            descriptor,
            now: now.addingTimeInterval(120)
        )
        XCTAssertEqual(stale.state, .stale)
        XCTAssertEqual(stale.stateReason, "artifact stale")
        XCTAssertTrue(stale.recordHeld)

        let snapshot = try store.inspectArtifacts(
            [descriptor],
            now: now.addingTimeInterval(120)
        )
        XCTAssertTrue(snapshot.snapshotHeld)
        XCTAssertEqual(snapshot.staleCount, 1)
        XCTAssertEqual(snapshot.validCount, 0)
        XCTAssertFalse(snapshot.productionCutoverAuthorized)
        XCTAssertFalse(snapshot.productionSecretRead)
        XCTAssertFalse(snapshot.productionEndpointConnected)
        XCTAssertFalse(snapshot.productionOrderSubmitted)

        XCTAssertThrowsError(
            try store.writeStringArtifact(
                descriptor: descriptor,
                string: payload,
                productionCutoverAuthorized: true
            )
        )
        XCTAssertThrowsError(
            try store.writeStringArtifact(
                descriptor: descriptor,
                string: "{\"productionCutoverAuthorized=true\": true}"
            )
        )
    }

    func testGH915ReadinessManifestSchemaAndAtomicIORequireRealArtifacts() throws {
        XCTAssertEqual(ProductionReadinessManifestAnchors.validationAnchors, [
            "GH-915-VERIFY-V0110-READINESS-MANIFEST-ATOMIC-IO",
            "TVM-RELEASE-V0110-READINESS-MANIFEST-ATOMIC-IO",
            "V0110-003-READINESS-MANIFEST-SCHEMA",
            "V0110-003-ATOMIC-JSON-ARTIFACT-IO",
            "V0110-003-MANIFEST-POLICY-VERSION",
            "V0110-003-MANIFEST-ENTRY-STATE-VALIDATION",
            "V0110-003-EVIDENCE-EXISTS-IS-NOT-SUFFICIENT"
        ])

        let evidenceRoot = FileManager.default.temporaryDirectory.appendingPathComponent(
            "MTPRO-GH915-ReadinessManifest-\(UUID().uuidString)",
            isDirectory: true
        )
        addTeardownBlock {
            try? FileManager.default.removeItem(at: evidenceRoot)
        }

        let store = try ProductionReadinessArtifactStore(evidenceRootURL: evidenceRoot)
        let artifactDescriptor = try ProductionReadinessArtifactDescriptor(
            artifactID: Identifier.constant("gh-915-risk-policy"),
            relativePath: "artifacts/risk-policy.json",
            artifactType: .jsonEvidence,
            staleAfterSeconds: 60
        )
        let manifestDescriptor = try ProductionReadinessArtifactDescriptor(
            artifactID: Identifier.constant("gh-915-readiness-manifest"),
            relativePath: "manifest/readiness-manifest.json",
            artifactType: .jsonEvidence
        )
        let now = Date(timeIntervalSince1970: 1_800_010_000)
        let policyVersion = "policy-v0.11.0-001"
        let payload = """
        {
          "artifactID": "gh-915-risk-policy",
          "policyVersion": "\(policyVersion)",
          "validationState": "valid",
          "redactionProof": true,
          "noSecretValue": true,
          "noOrderPayload": true,
          "productionTradingEnabledByDefault": false,
          "productionCutoverAuthorized": false,
          "productionSecretRead": false,
          "productionEndpointConnected": false,
          "brokerEndpointConnected": false,
          "productionOrderSubmitted": false,
          "testnetOrderSubmissionAllowed": false
        }
        """
        let artifactRecord = try store.writeStringArtifact(
            descriptor: artifactDescriptor,
            string: payload,
            modifiedAt: now
        )
        XCTAssertEqual(artifactRecord.state, .valid)

        let manifest = try store.writeReadinessManifest(
            manifestID: manifestDescriptor.artifactID,
            manifestRelativePath: manifestDescriptor.relativePath,
            descriptors: [artifactDescriptor],
            policyVersion: policyVersion,
            generatedAt: now.addingTimeInterval(1),
            now: now
        )
        XCTAssertTrue(manifest.manifestReadHeld)
        XCTAssertEqual(manifest.manifest.issueID.rawValue, "GH-915")
        XCTAssertEqual(manifest.manifest.releaseVersion, "v0.11.0")
        XCTAssertEqual(manifest.manifest.policyVersion, policyVersion)
        XCTAssertEqual(manifest.manifest.entries.count, 1)
        XCTAssertTrue(manifest.manifest.manifestHeld)
        XCTAssertFalse(manifest.manifest.productionCutoverAuthorized)
        XCTAssertFalse(manifest.manifest.productionSecretRead)
        XCTAssertFalse(manifest.manifest.productionEndpointConnected)
        XCTAssertFalse(manifest.manifest.productionOrderSubmitted)

        let entry = try XCTUnwrap(manifest.manifest.entries.first)
        XCTAssertEqual(entry.relativePath, artifactDescriptor.relativePath)
        XCTAssertEqual(entry.artifactType, .jsonEvidence)
        XCTAssertEqual(entry.staleAfterSeconds, 60)
        XCTAssertEqual(entry.size, Data(payload.utf8).count)
        XCTAssertEqual(entry.checksum, try ProductionReadinessArtifactStore.canonicalJSONSHA256Checksum(for: Data(payload.utf8)))
        XCTAssertTrue(ProductionReadinessArtifactStore.isValidSHA256Checksum(entry.checksum))
        XCTAssertEqual(entry.validationState, .valid)
        XCTAssertTrue(entry.evidenceExists)
        XCTAssertTrue(entry.entryHeld)

        let manifestText = String(decoding: manifest.data, as: UTF8.self)
        XCTAssertTrue(manifestText.contains("\"atomicWriteRequired\":true"))
        XCTAssertTrue(manifestText.contains("\"policyVersion\":\"\(policyVersion)\""))

        let readManifest = try store.readReadinessManifest(
            descriptor: manifestDescriptor,
            requiredPolicyVersion: policyVersion,
            now: now.addingTimeInterval(10)
        )
        XCTAssertEqual(readManifest.manifest, manifest.manifest)
        XCTAssertTrue(readManifest.manifestReadHeld)

        let secondManifest = try store.writeReadinessManifest(
            manifestID: manifestDescriptor.artifactID,
            manifestRelativePath: manifestDescriptor.relativePath,
            descriptors: [artifactDescriptor],
            policyVersion: policyVersion,
            generatedAt: now.addingTimeInterval(1),
            now: now
        )
        XCTAssertEqual(secondManifest.data, manifest.data)

        XCTAssertThrowsError(
            try store.readReadinessManifest(
                descriptor: manifestDescriptor,
                requiredPolicyVersion: "policy-v0.11.0-other",
                now: now.addingTimeInterval(10)
            )
        ) { error in
            guard case ProductionReadinessArtifactStoreError.manifestPolicyMismatch = error else {
                return XCTFail("expected manifestPolicyMismatch, got \(error)")
            }
        }

        let manifestURL = try store.artifactURL(for: manifestDescriptor)
        try Data("{\"evidenceExists\":true}".utf8).write(to: manifestURL, options: .atomic)
        try FileManager.default.setAttributes([.modificationDate: now], ofItemAtPath: manifestURL.path)
        XCTAssertThrowsError(
            try store.readReadinessManifest(
                descriptor: manifestDescriptor,
                requiredPolicyVersion: policyVersion,
                now: now.addingTimeInterval(10)
            )
        ) { error in
            guard case ProductionReadinessArtifactStoreError.invalidManifest = error else {
                return XCTFail("expected invalidManifest, got \(error)")
            }
        }

        _ = try store.writeReadinessManifest(
            manifestID: manifestDescriptor.artifactID,
            manifestRelativePath: manifestDescriptor.relativePath,
            descriptors: [artifactDescriptor],
            policyVersion: policyVersion,
            generatedAt: now.addingTimeInterval(1),
            now: now
        )
        XCTAssertThrowsError(
            try store.readReadinessManifest(
                descriptor: manifestDescriptor,
                requiredPolicyVersion: policyVersion,
                now: now.addingTimeInterval(120)
            )
        ) { error in
            guard case ProductionReadinessArtifactStoreError.manifestEntryRejected = error else {
                return XCTFail("expected manifestEntryRejected for stale artifact, got \(error)")
            }
        }

        try FileManager.default.removeItem(at: try store.artifactURL(for: artifactDescriptor))
        XCTAssertThrowsError(
            try store.readReadinessManifest(
                descriptor: manifestDescriptor,
                requiredPolicyVersion: policyVersion,
                now: now.addingTimeInterval(10)
            )
        ) { error in
            guard case ProductionReadinessArtifactStoreError.manifestEntryRejected = error else {
                return XCTFail("expected manifestEntryRejected for missing artifact despite evidenceExists=true, got \(error)")
            }
        }
    }

    func testGH916CanonicalJSONSHA256RejectsPlaceholderAndMismatchChecksums() throws {
        XCTAssertEqual(ProductionReadinessCanonicalChecksumAnchors.validationAnchors, [
            "GH-916-VERIFY-V0110-CANONICAL-JSON-SHA256-CHECKSUM",
            "TVM-RELEASE-V0110-CANONICAL-JSON-SHA256-CHECKSUM",
            "V0110-004-CANONICAL-JSON-SHA256",
            "V0110-004-CHECKSUM-FORMAT-VALIDATION",
            "V0110-004-CHECKSUM-MISMATCH-FAILS-CLOSED",
            "V0110-004-NO-PLACEHOLDER-CHECKSUMS"
        ])

        let sameObjectA = #"{"b":2,"a":1,"productionCutoverAuthorized":false}"#
        let sameObjectB = """
        {
          "productionCutoverAuthorized": false,
          "a": 1,
          "b": 2
        }
        """
        let canonicalA = try ProductionReadinessArtifactStore.canonicalJSONData(for: Data(sameObjectA.utf8))
        let canonicalB = try ProductionReadinessArtifactStore.canonicalJSONData(for: Data(sameObjectB.utf8))
        XCTAssertEqual(canonicalA, canonicalB)
        let checksum = try ProductionReadinessArtifactStore.canonicalJSONSHA256Checksum(for: Data(sameObjectA.utf8))
        XCTAssertEqual(checksum, try ProductionReadinessArtifactStore.canonicalJSONSHA256Checksum(for: Data(sameObjectB.utf8)))
        XCTAssertTrue(ProductionReadinessArtifactStore.isValidSHA256Checksum(checksum))
        XCTAssertEqual(checksum.count, "sha256:".count + 64)
        XCTAssertFalse(ProductionReadinessArtifactStore.isValidSHA256Checksum("sha256:gh890-secret-readiness"))
        XCTAssertFalse(ProductionReadinessArtifactStore.isValidSHA256Checksum("fnv1a64-0000000000000000"))

        let evidenceRoot = FileManager.default.temporaryDirectory.appendingPathComponent(
            "MTPRO-GH916-CanonicalSHA256-\(UUID().uuidString)",
            isDirectory: true
        )
        addTeardownBlock {
            try? FileManager.default.removeItem(at: evidenceRoot)
        }

        let store = try ProductionReadinessArtifactStore(evidenceRootURL: evidenceRoot)
        let artifactDescriptor = try ProductionReadinessArtifactDescriptor(
            artifactID: Identifier.constant("gh-916-readiness-artifact"),
            relativePath: "artifacts/readiness.json",
            artifactType: .jsonEvidence,
            staleAfterSeconds: 120
        )
        let manifestDescriptor = try ProductionReadinessArtifactDescriptor(
            artifactID: Identifier.constant("gh-916-readiness-manifest"),
            relativePath: "manifest/readiness-manifest.json",
            artifactType: .jsonEvidence
        )
        let now = Date(timeIntervalSince1970: 1_800_020_000)
        let policyVersion = "policy-v0.11.0-002"
        let artifactPayload = #"{"artifactID":"gh-916-risk","policyVersion":"policy-v0.11.0-002","productionCutoverAuthorized":false,"productionTradingEnabledByDefault":false}"#
        _ = try store.writeStringArtifact(
            descriptor: artifactDescriptor,
            string: artifactPayload,
            modifiedAt: now
        )
        let manifest = try store.writeReadinessManifest(
            manifestID: manifestDescriptor.artifactID,
            manifestRelativePath: manifestDescriptor.relativePath,
            descriptors: [artifactDescriptor],
            policyVersion: policyVersion,
            generatedAt: now.addingTimeInterval(1),
            now: now
        )
        let entry = try XCTUnwrap(manifest.manifest.entries.first)
        XCTAssertEqual(
            entry.checksum,
            try ProductionReadinessArtifactStore.canonicalJSONSHA256Checksum(for: Data(artifactPayload.utf8))
        )
        XCTAssertTrue(entry.checksum.hasPrefix("sha256:"))
        XCTAssertTrue(entry.entryHeld)

        let invalidChecksumManifest = String(decoding: manifest.data, as: UTF8.self)
            .replacingOccurrences(of: entry.checksum, with: "sha256:gh890-secret-readiness")
        let manifestURL = try store.artifactURL(for: manifestDescriptor)
        try Data(invalidChecksumManifest.utf8).write(to: manifestURL, options: .atomic)
        try FileManager.default.setAttributes([.modificationDate: now], ofItemAtPath: manifestURL.path)
        XCTAssertThrowsError(
            try store.readReadinessManifest(
                descriptor: manifestDescriptor,
                requiredPolicyVersion: policyVersion,
                now: now.addingTimeInterval(10)
            )
        ) { error in
            guard case ProductionReadinessArtifactStoreError.invalidChecksumFormat = error else {
                return XCTFail("expected invalidChecksumFormat for placeholder checksum, got \(error)")
            }
        }

        _ = try store.writeReadinessManifest(
            manifestID: manifestDescriptor.artifactID,
            manifestRelativePath: manifestDescriptor.relativePath,
            descriptors: [artifactDescriptor],
            policyVersion: policyVersion,
            generatedAt: now.addingTimeInterval(1),
            now: now
        )
        let driftedPayload = #"{"artifactID":"gh-916-fail","policyVersion":"policy-v0.11.0-002","productionCutoverAuthorized":false,"productionTradingEnabledByDefault":false}"#
        XCTAssertEqual(Data(driftedPayload.utf8).count, Data(artifactPayload.utf8).count)
        _ = try store.writeStringArtifact(
            descriptor: artifactDescriptor,
            string: driftedPayload,
            modifiedAt: now.addingTimeInterval(2)
        )
        XCTAssertThrowsError(
            try store.readReadinessManifest(
                descriptor: manifestDescriptor,
                requiredPolicyVersion: policyVersion,
                now: now.addingTimeInterval(10)
            )
        ) { error in
            guard case ProductionReadinessArtifactStoreError.checksumMismatch = error else {
                return XCTFail("expected checksumMismatch for canonical JSON drift, got \(error)")
            }
        }
    }

    func testGH948ProductionReadinessArtifactStoreRejectsSymlinkEscapes() throws {
        XCTAssertEqual(ProductionReadinessArtifactSymlinkRootAnchors.validationAnchors, [
            "GH-948-VERIFY-V0111-READINESS-ARTIFACT-SYMLINK-ROOT",
            "TVM-RELEASE-V0111-READINESS-ARTIFACT-SYMLINK-ROOT",
            "V0111-004-CANONICAL-EVIDENCE-ROOT",
            "V0111-004-NO-SYMLINK-PATH-COMPONENTS",
            "V0111-004-RESOLVED-TARGET-STAYS-IN-ROOT",
            "V0111-004-NO-PRODUCTION-CUTOVER"
        ])

        let fileManager = FileManager.default
        let tempRoot = fileManager.temporaryDirectory.appendingPathComponent(
            "MTPRO-GH948-SymlinkEscape-\(UUID().uuidString)",
            isDirectory: true
        )
        let evidenceRoot = tempRoot.appendingPathComponent("approved-root", isDirectory: true)
        let outsideRoot = tempRoot.appendingPathComponent("outside-root", isDirectory: true)
        addTeardownBlock {
            try? FileManager.default.removeItem(at: tempRoot)
        }
        try fileManager.createDirectory(at: evidenceRoot, withIntermediateDirectories: true)
        try fileManager.createDirectory(at: outsideRoot, withIntermediateDirectories: true)

        func assertUnsafeSymlink(_ operation: () throws -> Void) {
            XCTAssertThrowsError(try operation()) { error in
                guard case ProductionReadinessArtifactStoreError.unsafeSymbolicLink = error else {
                    return XCTFail("expected unsafeSymbolicLink, got \(error)")
                }
            }
        }

        let symlinkRoot = tempRoot.appendingPathComponent("approved-root-link", isDirectory: true)
        try fileManager.createSymbolicLink(at: symlinkRoot, withDestinationURL: outsideRoot)
        assertUnsafeSymlink {
            _ = try ProductionReadinessArtifactStore(evidenceRootURL: symlinkRoot)
        }

        let store = try ProductionReadinessArtifactStore(evidenceRootURL: evidenceRoot)
        let descriptor = try ProductionReadinessArtifactDescriptor(
            artifactID: Identifier.constant("gh-948-readiness-artifact"),
            relativePath: "artifacts/readiness.json",
            artifactType: .jsonEvidence,
            staleAfterSeconds: 120
        )
        let payload = """
        {
          "artifactID": "gh-948-readiness-artifact",
          "releaseVersion": "v0.11.1",
          "productionTradingEnabledByDefault": false,
          "productionCutoverAuthorized": false,
          "productionSecretRead": false,
          "productionEndpointConnected": false,
          "brokerEndpointConnected": false,
          "productionOrderSubmitted": false,
          "testnetOrderSubmissionAllowed": false
        }
        """

        let symlinkDirectory = evidenceRoot.appendingPathComponent("artifacts", isDirectory: true)
        try fileManager.createSymbolicLink(at: symlinkDirectory, withDestinationURL: outsideRoot)
        assertUnsafeSymlink {
            _ = try store.writeStringArtifact(descriptor: descriptor, string: payload)
        }
        try fileManager.removeItem(at: symlinkDirectory)
        try fileManager.createDirectory(at: symlinkDirectory, withIntermediateDirectories: true)

        let outsideArtifact = outsideRoot.appendingPathComponent("readiness.json")
        try Data(payload.utf8).write(to: outsideArtifact, options: .atomic)
        let symlinkArtifact = symlinkDirectory.appendingPathComponent("readiness.json")
        try fileManager.createSymbolicLink(at: symlinkArtifact, withDestinationURL: outsideArtifact)
        assertUnsafeSymlink {
            _ = try store.inspectArtifact(descriptor)
        }
        assertUnsafeSymlink {
            _ = try store.readArtifact(descriptor: descriptor)
        }
        assertUnsafeSymlink {
            _ = try store.writeStringArtifact(descriptor: descriptor, string: payload)
        }

        try fileManager.removeItem(at: symlinkArtifact)
        let valid = try store.writeStringArtifact(
            descriptor: descriptor,
            string: payload,
            modifiedAt: Date(timeIntervalSince1970: 1_800_110_000)
        )
        XCTAssertEqual(valid.state, .valid)
        XCTAssertTrue(valid.absolutePath.hasPrefix(evidenceRoot.path))
        XCTAssertTrue(valid.productionCapabilitiesDisabled)
    }

    func testGH949ProductionReadinessArtifactStoreEnforcesOwnerOnlyPermissions() throws {
        XCTAssertEqual(ProductionReadinessArtifactPermissionAnchors.validationAnchors, [
            "GH-949-VERIFY-V0111-READINESS-ARTIFACT-PERMISSIONS",
            "TVM-RELEASE-V0111-READINESS-ARTIFACT-PERMISSIONS",
            "V0111-005-OWNER-ONLY-DIRECTORIES",
            "V0111-005-OWNER-ONLY-FILES",
            "V0111-005-PERMISSION-REPAIR",
            "V0111-005-NO-PRODUCTION-CUTOVER"
        ])
        XCTAssertEqual(ProductionReadinessArtifactStore.ownerOnlyDirectoryPermissions, 0o700)
        XCTAssertEqual(ProductionReadinessArtifactStore.ownerOnlyFilePermissions, 0o600)

        let fileManager = FileManager.default
        let tempRoot = fileManager.temporaryDirectory.appendingPathComponent(
            "MTPRO-GH949-ArtifactPermissions-\(UUID().uuidString)",
            isDirectory: true
        )
        let evidenceRoot = tempRoot.appendingPathComponent("approved-root", isDirectory: true)
        let broadDirectory = evidenceRoot.appendingPathComponent("broad/permissions", isDirectory: true)
        addTeardownBlock {
            try? FileManager.default.removeItem(at: tempRoot)
        }
        try fileManager.createDirectory(at: broadDirectory, withIntermediateDirectories: true)
        try fileManager.setAttributes([.posixPermissions: 0o777], ofItemAtPath: evidenceRoot.path)
        try fileManager.setAttributes([.posixPermissions: 0o777], ofItemAtPath: broadDirectory.path)

        func permissionBits(_ url: URL) throws -> Int {
            let attributes = try fileManager.attributesOfItem(atPath: url.path)
            guard let permissions = attributes[.posixPermissions] as? NSNumber else {
                XCTFail("expected POSIX permissions for \(url.path)")
                return -1
            }
            return permissions.intValue & 0o777
        }

        let store = try ProductionReadinessArtifactStore(evidenceRootURL: evidenceRoot)
        let descriptor = try ProductionReadinessArtifactDescriptor(
            artifactID: Identifier.constant("gh-949-readiness-artifact"),
            relativePath: "broad/permissions/readiness.json",
            artifactType: .jsonEvidence,
            staleAfterSeconds: 120
        )
        let modifiedAt = Date(timeIntervalSince1970: 1_800_111_000)
        let payload = """
        {
          "artifactID": "gh-949-readiness-artifact",
          "releaseVersion": "v0.11.1",
          "productionTradingEnabledByDefault": false,
          "productionCutoverAuthorized": false,
          "productionSecretRead": false,
          "productionEndpointConnected": false,
          "brokerEndpointConnected": false,
          "productionOrderSubmitted": false,
          "testnetOrderSubmissionAllowed": false
        }
        """

        let record = try store.writeStringArtifact(
            descriptor: descriptor,
            string: payload,
            modifiedAt: modifiedAt
        )

        XCTAssertEqual(record.state, .valid)
        XCTAssertTrue(record.productionCapabilitiesDisabled)
        XCTAssertEqual(try permissionBits(evidenceRoot), 0o700)
        XCTAssertEqual(try permissionBits(evidenceRoot.appendingPathComponent("broad", isDirectory: true)), 0o700)
        XCTAssertEqual(try permissionBits(broadDirectory), 0o700)
        XCTAssertEqual(try permissionBits(URL(fileURLWithPath: record.absolutePath)), 0o600)
        XCTAssertEqual(record.modifiedAt, modifiedAt)
    }

