    func testGH954ReadinessAssessmentRegistryStorePersistsLifecycleAndCompareReadyMetadata() throws {
        // 测试场景：GH-954 只把多次 readiness assessment 历史写入本地 registry；
        // compare-ready 仍是本地 metadata state，不是 cutover、broker 或 order authority。
        let expectedRegistryAnchors = [
            "GH-954-VERIFY-V0120-READINESS-ASSESSMENT-REGISTRY-STORE",
            "TVM-RELEASE-V0120-READINESS-ASSESSMENT-REGISTRY-STORE",
            "V0120-003-READINESS-ASSESSMENT-REGISTRY-STORE",
            "V0120-003-REGISTRY-JSON-PATH",
            "V0120-003-ASSESSMENT-DIRECTORY-PATH",
            "V0120-003-CREATE-LIST-INSPECT-ARCHIVE-RECOVER",
            "V0120-003-COMPARE-READY-METADATA",
            "V0120-003-NO-PRODUCTION-CUTOVER",
            "GH-955-VERIFY-V0120-ASSESSMENT-TRANSACTION-LOCK",
            "TVM-RELEASE-V0120-ASSESSMENT-TRANSACTION-LOCK",
            "V0120-004-ASSESSMENT-TRANSACTION-LOCK",
            "V0120-004-TRANSACTION-ID-GENERATION-ID",
            "V0120-004-STAGING-DIRECTORY-COMMIT-MARKER",
            "V0120-004-COMPARE-AND-SWAP-MANIFEST",
            "V0120-004-CRASH-RECOVERY-SEMANTICS",
            "V0120-004-NO-PRODUCTION-CUTOVER",
            "GH-956-VERIFY-V0120-READINESS-MANIFEST-V2",
            "TVM-RELEASE-V0120-READINESS-MANIFEST-V2",
            "V0120-005-READINESS-MANIFEST-V2",
            "V0120-005-ASSESSMENT-GENERATION-PROVENANCE",
            "V0120-005-SOURCE-RUN-COMMIT-PROVENANCE",
            "V0120-005-CANONICAL-ARTIFACT-METADATA",
            "V0120-005-PRODUCER-VERSION-SCHEMA",
            "V0120-005-NO-PRODUCTION-CUTOVER",
            "GH-957-VERIFY-V0120-ARTIFACT-CONTENT-POLICY-REDACTION",
            "TVM-RELEASE-V0120-ARTIFACT-CONTENT-POLICY-REDACTION",
            "V0120-006-ARTIFACT-CONTENT-POLICY",
            "V0120-006-JSON-SCHEMA-ALLOWLIST",
            "V0120-006-FORBIDDEN-FIELD-REJECTION",
            "V0120-006-RAW-SECRET-LISTENKEY-REJECTION",
            "V0120-006-ORDER-ENDPOINT-PAYLOAD-REJECTION",
            "V0120-006-CONTENT-VALIDATION-CHECKSUM",
            "V0120-006-NO-PRODUCTION-CUTOVER"
        ]
        for anchor in expectedRegistryAnchors {
            XCTAssertTrue(
                ReadinessAssessmentRegistryStoreAnchors.validationAnchors.contains(anchor),
                "\(anchor) must stay in registry store anchors"
            )
        }
        XCTAssertEqual(
            ReadinessAssessmentRegistryState.allCases.map(\.rawValue),
            [
                "baseline",
                "follow-up",
                "ready",
                "compare-ready",
                "blocked",
                "incomplete",
                "invalid",
                "stale",
                "superseded",
                "archived",
                "recovered"
            ]
        )

        let root = FileManager.default.temporaryDirectory
            .appendingPathComponent("MTPRO-GH954-ReadinessAssessmentRegistry-\(UUID().uuidString)", isDirectory: true)
        addTeardownBlock {
            try? FileManager.default.removeItem(at: root)
        }

        let store = ReadinessAssessmentRegistryStore(storageRootURL: root)
        let createdAt = Date(timeIntervalSince1970: 1_812_000_000)
        let updatedAt = Date(timeIntervalSince1970: 1_812_000_120)
        let baselineID = Identifier.constant("gh-954-baseline-assessment")
        let followUpID = Identifier.constant("gh-954-follow-up-assessment")

        let baselineDocument = try store.create(
            assessmentID: baselineID,
            state: .baseline,
            sourceReleaseVersion: "v0.11.0",
            sourcePatchVersion: "v0.11.1",
            assessedBy: "Codex",
            reason: "baseline assessment imported from v0.11.x release facts",
            createdAt: createdAt,
            updatedAt: updatedAt
        )
        XCTAssertEqual(baselineDocument.registryPath, ".local/mtpro/readiness/registry.json")
        XCTAssertEqual(baselineDocument.assessmentsRootPath, ".local/mtpro/readiness/assessments")
        XCTAssertTrue(baselineDocument.documentHeld)
        XCTAssertTrue(FileManager.default.fileExists(atPath: root.appendingPathComponent("registry.json").path))
        XCTAssertTrue(
            FileManager.default.fileExists(
                atPath: root
                    .appendingPathComponent("assessments", isDirectory: true)
                    .appendingPathComponent(baselineID.rawValue, isDirectory: true)
                    .path
            )
        )

        let compareDocument = try store.create(
            assessmentID: followUpID,
            state: .compareReady,
            sourceReleaseVersion: "v0.12.0",
            comparisonBaseAssessmentID: baselineID,
            assessedBy: "Codex",
            reason: "follow-up assessment ready for local diff",
            createdAt: createdAt,
            updatedAt: updatedAt.addingTimeInterval(60)
        )
        XCTAssertEqual(compareDocument.entries.map(\.assessmentID.rawValue), [
            baselineID.rawValue,
            followUpID.rawValue
        ])
        XCTAssertEqual(try store.listAssessments().count, 2)
        XCTAssertEqual(try store.inspect(assessmentID: followUpID).state, .compareReady)
        XCTAssertEqual(try store.compareReadyAssessments().map(\.assessmentID.rawValue), [followUpID.rawValue])

        let archivedDocument = try store.archive(
            assessmentID: followUpID,
            updatedAt: updatedAt.addingTimeInterval(120)
        )
        let archivedEntry = try archivedDocument.inspect(assessmentID: followUpID)
        XCTAssertEqual(archivedEntry.lifecycle, .archived)
        XCTAssertEqual(archivedEntry.state, .archived)
        XCTAssertTrue(try store.compareReadyAssessments().isEmpty)

        let recoveredDocument = try store.recover(
            assessmentID: baselineID,
            reason: "registry metadata recovery evidence",
            updatedAt: updatedAt.addingTimeInterval(180)
        )
        let recoveredEntry = try recoveredDocument.inspect(assessmentID: baselineID)
        XCTAssertEqual(recoveredEntry.lifecycle, .recoveryEvidence)
        XCTAssertEqual(recoveredEntry.state, .recovered)
        XCTAssertEqual(recoveredEntry.recoveryReason, "registry metadata recovery evidence")

        XCTAssertThrowsError(
            try store.recover(
                assessmentID: followUpID,
                reason: "archived entries stay immutable",
                updatedAt: updatedAt.addingTimeInterval(240)
            )
        ) { error in
            XCTAssertEqual(
                error as? ReadinessAssessmentRegistryStoreError,
                .cannotMutateArchivedAssessment(followUpID.rawValue)
            )
        }
        XCTAssertThrowsError(
            try store.create(
                assessmentID: Identifier.constant("../escape"),
                state: .ready,
                sourceReleaseVersion: "v0.12.0",
                assessedBy: "Codex",
                reason: "unsafe path component",
                createdAt: createdAt,
                updatedAt: updatedAt
            )
        ) { error in
            XCTAssertEqual(
                error as? ReadinessAssessmentRegistryStoreError,
                .unsafeAssessmentID("../escape")
            )
        }

        let loaded = try store.load()
        XCTAssertTrue(loaded.documentHeld)
        XCTAssertEqual(
            loaded.registryChecksum,
            ReadinessAssessmentRegistryDocument.stableRegistryChecksum(
                entries: loaded.entries,
                createdAt: loaded.createdAt,
                updatedAt: loaded.updatedAt
            )
        )
        XCTAssertFalse(loaded.productionTradingEnabledByDefault)
        XCTAssertFalse(loaded.productionCutoverAuthorized)
        XCTAssertFalse(loaded.productionSecretRead)
        XCTAssertFalse(loaded.productionEndpointConnected)
        XCTAssertFalse(loaded.brokerEndpointConnected)
        XCTAssertFalse(loaded.productionBrokerConnected)
        XCTAssertFalse(loaded.productionOrderSubmitted)
        XCTAssertFalse(loaded.realOrderSubmissionEnabled)
        XCTAssertFalse(loaded.testnetOrderSubmissionAllowed)
        XCTAssertFalse(loaded.testnetOrderRoutingAllowed)

        let encodedRegistry = try XCTUnwrap(
            String(data: JSONEncoder().encode(loaded), encoding: .utf8)
        )
        for forbidden in [
            "productionTradingEnabledByDefault\":true",
            "productionCutoverAuthorized\":true",
            "productionSecretRead\":true",
            "productionEndpointConnected\":true",
            "brokerEndpointConnected\":true",
            "productionBrokerConnected\":true",
            "productionOrderSubmitted\":true",
            "realOrderSubmissionEnabled\":true",
            "testnetOrderSubmissionAllowed\":true",
            "testnetOrderRoutingAllowed\":true"
        ] {
            XCTAssertFalse(encodedRegistry.contains(forbidden), "\(forbidden) must stay false in GH-954 registry")
        }
    }

    func testGH955AssessmentTransactionLockControlsGenerationAndCrashRecovery() throws {
        // 测试场景：GH-955 在 GH-954 registry store 上增加本地 transaction / generation
        // 控制；所有锁、staging、commit marker 和 CAS manifest 都是本地证据，不是生产交易授权。
        XCTAssertTrue(
            ReadinessAssessmentRegistryStoreAnchors.validationAnchors.contains(
                "GH-955-VERIFY-V0120-ASSESSMENT-TRANSACTION-LOCK"
            )
        )
        XCTAssertTrue(
            ReadinessAssessmentRegistryStoreAnchors.validationAnchors.contains(
                "V0120-004-COMPARE-AND-SWAP-MANIFEST"
            )
        )

        let root = FileManager.default.temporaryDirectory
            .appendingPathComponent("MTPRO-GH955-AssessmentTransactionLock-\(UUID().uuidString)", isDirectory: true)
        addTeardownBlock {
            try? FileManager.default.removeItem(at: root)
        }

        let store = ReadinessAssessmentRegistryStore(storageRootURL: root)
        let createdAt = Date(timeIntervalSince1970: 1_812_100_000)
        let updatedAt = Date(timeIntervalSince1970: 1_812_100_120)
        let assessmentID = Identifier.constant("gh-955-assessment")
        let firstTransactionID = Identifier.constant("gh-955-tx-1")
        let firstGenerationID = Identifier.constant("gh-955-gen-1")

        let firstResult = try store.createWithTransaction(
            assessmentID: assessmentID,
            transactionID: firstTransactionID,
            generationID: firstGenerationID,
            expectedPreviousGenerationID: nil,
            state: .ready,
            sourceReleaseVersion: "v0.12.0",
            assessedBy: "Codex",
            reason: "transactional readiness assessment write",
            createdAt: createdAt,
            updatedAt: updatedAt
        )
        XCTAssertTrue(firstResult.control.controlHeld)
        XCTAssertTrue(firstResult.manifest.manifestHeld)
        XCTAssertTrue(firstResult.commitMarker.markerHeld)
        XCTAssertEqual(firstResult.manifest.currentGenerationID, firstGenerationID)
        XCTAssertNil(firstResult.manifest.previousGenerationID)
        XCTAssertEqual(firstResult.document.entries.map(\.assessmentID.rawValue), [assessmentID.rawValue])
        XCTAssertFalse(firstResult.document.productionCutoverAuthorized)

        let assessmentDirectory = root
            .appendingPathComponent("assessments", isDirectory: true)
            .appendingPathComponent(assessmentID.rawValue, isDirectory: true)
        XCTAssertTrue(
            FileManager.default.fileExists(
                atPath: assessmentDirectory
                    .appendingPathComponent("compare-and-swap-manifest.json", isDirectory: false)
                    .path
            )
        )
        XCTAssertTrue(
            FileManager.default.fileExists(
                atPath: assessmentDirectory
                    .appendingPathComponent("commit-marker.json", isDirectory: false)
                    .path
            )
        )
        XCTAssertFalse(
            FileManager.default.fileExists(
                atPath: root
                    .appendingPathComponent("staging", isDirectory: true)
                    .appendingPathComponent(assessmentID.rawValue, isDirectory: true)
                    .appendingPathComponent(firstTransactionID.rawValue, isDirectory: true)
                    .path
            )
        )

        XCTAssertThrowsError(
            try store.createWithTransaction(
                assessmentID: assessmentID,
                transactionID: Identifier.constant("gh-955-tx-2"),
                generationID: Identifier.constant("gh-955-gen-2"),
                expectedPreviousGenerationID: nil,
                state: .ready,
                sourceReleaseVersion: "v0.12.0",
                assessedBy: "Codex",
                reason: "stale writer must fail compare-and-swap",
                createdAt: createdAt,
                updatedAt: updatedAt.addingTimeInterval(60)
            )
        ) { error in
            XCTAssertEqual(
                error as? ReadinessAssessmentRegistryStoreError,
                .concurrentModification(expected: "<none>", actual: firstGenerationID.rawValue)
            )
        }

        XCTAssertThrowsError(
            try store.createWithTransaction(
                assessmentID: assessmentID,
                transactionID: Identifier.constant("gh-955-tx-3"),
                generationID: firstGenerationID,
                expectedPreviousGenerationID: firstGenerationID,
                state: .ready,
                sourceReleaseVersion: "v0.12.0",
                assessedBy: "Codex",
                reason: "generation must advance",
                createdAt: createdAt,
                updatedAt: updatedAt.addingTimeInterval(120)
            )
        ) { error in
            XCTAssertEqual(
                error as? ReadinessAssessmentRegistryStoreError,
                .generationMismatch(
                    expected: "new generation different from \(firstGenerationID.rawValue)",
                    actual: firstGenerationID.rawValue
                )
            )
        }

        let lockedAssessmentID = Identifier.constant("gh-955-locked-assessment")
        let lockedAssessmentDirectory = root
            .appendingPathComponent("assessments", isDirectory: true)
            .appendingPathComponent(lockedAssessmentID.rawValue, isDirectory: true)
        try FileManager.default.createDirectory(
            at: lockedAssessmentDirectory.appendingPathComponent("assessment.lock", isDirectory: true),
            withIntermediateDirectories: true
        )
        XCTAssertThrowsError(
            try store.createWithTransaction(
                assessmentID: lockedAssessmentID,
                transactionID: Identifier.constant("gh-955-locked-tx"),
                generationID: Identifier.constant("gh-955-locked-gen"),
                expectedPreviousGenerationID: nil,
                state: .ready,
                sourceReleaseVersion: "v0.12.0",
                assessedBy: "Codex",
                reason: "lock unavailable",
                createdAt: createdAt,
                updatedAt: updatedAt
            )
        ) { error in
            XCTAssertEqual(
                error as? ReadinessAssessmentRegistryStoreError,
                .lockUnavailable(".local/mtpro/readiness/assessments/\(lockedAssessmentID.rawValue)/assessment.lock")
            )
        }

        let abortControl = try store.stageAssessmentTransaction(
            assessmentID: Identifier.constant("gh-955-abort-assessment"),
            transactionID: Identifier.constant("gh-955-abort-tx"),
            generationID: Identifier.constant("gh-955-abort-gen"),
            expectedPreviousGenerationID: nil,
            startedAt: createdAt
        )
        XCTAssertTrue(
            FileManager.default.fileExists(
                atPath: root
                    .appendingPathComponent("staging", isDirectory: true)
                    .appendingPathComponent(abortControl.assessmentID.rawValue, isDirectory: true)
                    .appendingPathComponent(abortControl.transactionID.rawValue, isDirectory: true)
                    .path
            )
        )
        let abortMarker = try store.abortAssessmentTransaction(
            control: abortControl,
            reason: "operator aborted local assessment transaction",
            abortedAt: updatedAt.addingTimeInterval(180)
        )
        XCTAssertTrue(abortMarker.abortHeld)
        XCTAssertFalse(
            FileManager.default.fileExists(
                atPath: root
                    .appendingPathComponent("staging", isDirectory: true)
                    .appendingPathComponent(abortControl.assessmentID.rawValue, isDirectory: true)
                    .appendingPathComponent(abortControl.transactionID.rawValue, isDirectory: true)
                    .path
            )
        )

        let crashControl = try store.stageAssessmentTransaction(
            assessmentID: Identifier.constant("gh-955-crash-assessment"),
            transactionID: Identifier.constant("gh-955-crash-tx"),
            generationID: Identifier.constant("gh-955-crash-gen"),
            expectedPreviousGenerationID: nil,
            startedAt: createdAt
        )
        let recovery = try store.recoverInterruptedTransactions(recoveredAt: updatedAt.addingTimeInterval(240))
        XCTAssertTrue(recovery.recoveryHeld)
        XCTAssertTrue(
            recovery.recoveredStagingDirectoryPaths.contains(
                ".local/mtpro/readiness/staging/\(crashControl.assessmentID.rawValue)/\(crashControl.transactionID.rawValue)"
            )
        )
        XCTAssertTrue(
            recovery.recoveredAssessmentLockPaths.contains(
                ".local/mtpro/readiness/assessments/\(crashControl.assessmentID.rawValue)/assessment.lock"
            )
        )
        XCTAssertTrue(
            recovery.recoveredAssessmentLockPaths.contains(
                ".local/mtpro/readiness/assessments/\(lockedAssessmentID.rawValue)/assessment.lock"
            )
        )
        XCTAssertFalse(recovery.productionCutoverAuthorized)
        XCTAssertFalse(recovery.productionOrderSubmitted)
    }

    func testGH956ReadinessManifestV2RecordsAssessmentGenerationAndProvenance() throws {
        // 测试场景：GH-956 为 v0.12.0 assessment 增加 Manifest V2 / provenance schema。
        // 该 schema 只记录本地 artifact provenance，不授权 production cutover、secret、
        // endpoint、broker、OMS 或订单命令。
        XCTAssertTrue(
            ReadinessAssessmentRegistryStoreAnchors.validationAnchors.contains(
                "GH-956-VERIFY-V0120-READINESS-MANIFEST-V2"
            )
        )
        XCTAssertTrue(
            ReadinessAssessmentRegistryStoreAnchors.validationAnchors.contains(
                "V0120-005-CANONICAL-ARTIFACT-METADATA"
            )
        )

        let root = FileManager.default.temporaryDirectory
            .appendingPathComponent("MTPRO-GH956-ReadinessManifestV2-\(UUID().uuidString)", isDirectory: true)
        addTeardownBlock {
            try? FileManager.default.removeItem(at: root)
        }

        let store = ReadinessAssessmentRegistryStore(storageRootURL: root)
        let createdAt = Date(timeIntervalSince1970: 1_812_200_000)
        let assessmentID = Identifier.constant("gh-956-assessment")
        let generationID = Identifier.constant("gh-956-generation-1")
        let sourceRunA = Identifier.constant("gh-956-run-a")
        let sourceRunB = Identifier.constant("gh-956-run-b")
        let sourceCommit = "0354aeefc0b9f4c74ae8fa9cc80a60787b28860d"
        let artifactSHA256 = "sha256:\(String(repeating: "a", count: 64))"

        let manifest = try ReadinessAssessmentManifestV2(
            assessmentID: assessmentID,
            generationID: generationID,
            sourceRunIDs: [sourceRunB, sourceRunA],
            sourceCommit: sourceCommit,
            artifactContentType: .jsonEvidence,
            artifactSHA256: artifactSHA256,
            artifactBytes: 4096,
            createdAt: createdAt,
            producerVersion: "mtpro-v0.12.0-gh956"
        )
        XCTAssertTrue(manifest.manifestHeld)
        XCTAssertEqual(manifest.schemaVersion, ReadinessAssessmentManifestV2.schemaVersion)
        XCTAssertEqual(manifest.canonicalizationAlgorithm, ReadinessAssessmentManifestV2.canonicalizationAlgorithm)
        XCTAssertEqual(manifest.artifactContentType, .jsonEvidence)
        XCTAssertEqual(manifest.sourceRunIDs.map(\.rawValue), [sourceRunA.rawValue, sourceRunB.rawValue])
        XCTAssertEqual(manifest.sourceCommit, sourceCommit)
        XCTAssertEqual(manifest.artifactSHA256, artifactSHA256)
        XCTAssertEqual(manifest.artifactBytes, 4096)
        XCTAssertEqual(manifest.producerVersion, "mtpro-v0.12.0-gh956")
        XCTAssertEqual(
            manifest.manifestChecksum,
            ReadinessAssessmentManifestV2.stableManifestChecksum(
                assessmentID: assessmentID,
                generationID: generationID,
                sourceRunIDs: [sourceRunA, sourceRunB],
                sourceCommit: sourceCommit,
                artifactContentType: .jsonEvidence,
                artifactSHA256: artifactSHA256,
                artifactBytes: 4096,
                createdAt: createdAt,
                producerVersion: "mtpro-v0.12.0-gh956"
            )
        )
        XCTAssertEqual(
            manifest.manifestV2Path,
            ".local/mtpro/readiness/assessments/\(assessmentID.rawValue)/manifest-v2.json"
        )
        XCTAssertFalse(manifest.productionTradingEnabledByDefault)
        XCTAssertFalse(manifest.productionCutoverAuthorized)
        XCTAssertFalse(manifest.productionSecretRead)
        XCTAssertFalse(manifest.productionEndpointConnected)
        XCTAssertFalse(manifest.brokerEndpointConnected)
        XCTAssertFalse(manifest.productionBrokerConnected)
        XCTAssertFalse(manifest.productionOrderSubmitted)
        XCTAssertFalse(manifest.realOrderSubmissionEnabled)
        XCTAssertFalse(manifest.testnetOrderSubmissionAllowed)
        XCTAssertFalse(manifest.testnetOrderRoutingAllowed)

        let written = try store.writeManifestV2(manifest)
        XCTAssertEqual(written, manifest)
        let manifestURL = root
            .appendingPathComponent("assessments", isDirectory: true)
            .appendingPathComponent(assessmentID.rawValue, isDirectory: true)
            .appendingPathComponent("manifest-v2.json", isDirectory: false)
        XCTAssertTrue(FileManager.default.fileExists(atPath: manifestURL.path))
        let decoded = try store.readManifestV2(assessmentID: assessmentID)
        XCTAssertEqual(decoded, manifest)

        let encodedManifest = try XCTUnwrap(
            String(data: JSONEncoder().encode(decoded), encoding: .utf8)
        )
        for required in [
            "\"assessmentID\"",
            "\"generationID\"",
            "\"sourceRunIDs\"",
            "\"sourceCommit\"",
            "\"schemaVersion\"",
            "\"canonicalizationAlgorithm\"",
            "\"artifactContentType\"",
            "\"artifactSHA256\"",
            "\"artifactBytes\"",
            "\"createdAt\"",
            "\"producerVersion\""
        ] {
            XCTAssertTrue(encodedManifest.contains(required), "\(required) must be encoded in Manifest V2")
        }
        for forbidden in [
            "productionTradingEnabledByDefault\":true",
            "productionCutoverAuthorized\":true",
            "productionSecretRead\":true",
            "productionEndpointConnected\":true",
            "brokerEndpointConnected\":true",
            "productionBrokerConnected\":true",
            "productionOrderSubmitted\":true",
            "realOrderSubmissionEnabled\":true",
            "testnetOrderSubmissionAllowed\":true",
            "testnetOrderRoutingAllowed\":true"
        ] {
            XCTAssertFalse(encodedManifest.contains(forbidden), "\(forbidden) must stay false in GH-956 manifest")
        }

        XCTAssertThrowsError(
            try ReadinessAssessmentManifestV2(
                assessmentID: assessmentID,
                generationID: generationID,
                sourceRunIDs: [sourceRunA],
                sourceCommit: "not-a-commit",
                artifactContentType: .jsonEvidence,
                artifactSHA256: artifactSHA256,
                artifactBytes: 1,
                createdAt: createdAt,
                producerVersion: "mtpro-v0.12.0-gh956"
            )
        ) { error in
            XCTAssertEqual(error as? ReadinessAssessmentRegistryStoreError, .boundaryDrift("readinessManifestV2"))
        }
        XCTAssertThrowsError(
            try ReadinessAssessmentManifestV2(
                assessmentID: assessmentID,
                generationID: generationID,
                sourceRunIDs: [],
                sourceCommit: sourceCommit,
                artifactContentType: .jsonEvidence,
                artifactSHA256: artifactSHA256,
                artifactBytes: 1,
                createdAt: createdAt,
                producerVersion: "mtpro-v0.12.0-gh956"
            )
        ) { error in
            XCTAssertEqual(error as? ReadinessAssessmentRegistryStoreError, .boundaryDrift("readinessManifestV2"))
        }
        XCTAssertThrowsError(
            try ReadinessAssessmentManifestV2(
                assessmentID: assessmentID,
                generationID: generationID,
                sourceRunIDs: [sourceRunA],
                sourceCommit: sourceCommit,
                artifactContentType: .jsonEvidence,
                artifactSHA256: "sha256:not-valid",
                artifactBytes: 1,
                createdAt: createdAt,
                producerVersion: "mtpro-v0.12.0-gh956"
            )
        ) { error in
            XCTAssertEqual(error as? ReadinessAssessmentRegistryStoreError, .boundaryDrift("readinessManifestV2"))
        }
        XCTAssertThrowsError(
            try ReadinessAssessmentManifestV2(
                assessmentID: assessmentID,
                generationID: generationID,
                sourceRunIDs: [sourceRunA],
                sourceCommit: sourceCommit,
                artifactContentType: .jsonEvidence,
                artifactSHA256: artifactSHA256,
                artifactBytes: 0,
                createdAt: createdAt,
                producerVersion: "mtpro-v0.12.0-gh956"
            )
        ) { error in
            XCTAssertEqual(error as? ReadinessAssessmentRegistryStoreError, .boundaryDrift("readinessManifestV2"))
        }
    }

    func testGH957ArtifactContentPolicyRejectsSecretsListenKeysOrdersAndEndpointResponses() throws {
        // 测试场景：GH-957 在 Manifest V2 之后增加 per-artifact content policy / redaction validator。
        // Validator 只校验本地 JSON evidence bytes，不读取 secret、不连接 endpoint / broker、
        // 不提交 testnet / production order，也不授权 production cutover。
        XCTAssertTrue(
            ReadinessAssessmentRegistryStoreAnchors.validationAnchors.contains(
                "GH-957-VERIFY-V0120-ARTIFACT-CONTENT-POLICY-REDACTION"
            )
        )
        XCTAssertTrue(
            ReadinessAssessmentRegistryStoreAnchors.validationAnchors.contains(
                "V0120-006-CONTENT-VALIDATION-CHECKSUM"
            )
        )
        XCTAssertEqual(ReadinessAssessmentArtifactContentValidationState.allCases.map(\.rawValue), ["valid"])

        let root = FileManager.default.temporaryDirectory
            .appendingPathComponent("MTPRO-GH957-ArtifactContentPolicy-\(UUID().uuidString)", isDirectory: true)
        addTeardownBlock {
            try? FileManager.default.removeItem(at: root)
        }

        let store = ReadinessAssessmentRegistryStore(storageRootURL: root)
        let artifactID = Identifier.constant("gh-957-redacted-artifact")
        let policyVersion = "policy-v0.12.0-006"
        let allowedFields = [
            "artifactID",
            "contentChecksum",
            "noOrderPayload",
            "noSecretValue",
            "policyVersion",
            "productionCutoverAuthorized",
            "redactionProof"
        ]
        let requiredFields = [
            "artifactID",
            "noOrderPayload",
            "noSecretValue",
            "policyVersion",
            "productionCutoverAuthorized",
            "redactionProof"
        ]
        let policy = try ReadinessAssessmentArtifactContentPolicy(
            policyVersion: policyVersion,
            artifactID: artifactID,
            allowedJSONFields: allowedFields,
            requiredJSONFields: requiredFields
        )
        XCTAssertTrue(policy.policyHeld)
        XCTAssertEqual(policy.allowedJSONFields, allowedFields.sorted())
        XCTAssertTrue(policy.forbiddenJSONFields.contains("secret"))
        XCTAssertTrue(policy.forbiddenJSONFields.contains("listenKey"))
        XCTAssertTrue(policy.forbiddenRawMarkers.contains("api.binance.com"))

        let validPayload = #"{"artifactID":"gh-957-redacted-artifact","contentChecksum":"sha256:aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa","noOrderPayload":true,"noSecretValue":true,"policyVersion":"policy-v0.12.0-006","productionCutoverAuthorized":false,"redactionProof":true}"#
        let validData = Data(validPayload.utf8)
        let validArtifactSHA = try ProductionReadinessArtifactStore.canonicalJSONSHA256Checksum(for: validData)
        let manifest = try ReadinessAssessmentManifestV2(
            assessmentID: Identifier.constant("gh-957-assessment"),
            generationID: Identifier.constant("gh-957-generation-1"),
            sourceRunIDs: [Identifier.constant("gh-957-source-run")],
            sourceCommit: "6e6f59382546419cf4e04c24635815d44a72a008",
            artifactContentType: .jsonEvidence,
            artifactSHA256: validArtifactSHA,
            artifactBytes: validData.count,
            createdAt: Date(timeIntervalSince1970: 1_812_300_000),
            producerVersion: "mtpro-v0.12.0-gh957"
        )
        let validatedAt = Date(timeIntervalSince1970: 1_812_300_120)
        let result = try store.validateArtifactContent(
            data: validData,
            manifest: manifest,
            policy: policy,
            validatedAt: validatedAt
        )
        XCTAssertTrue(result.validationHeld)
        XCTAssertEqual(result.validationState, .valid)
        XCTAssertEqual(result.artifactID, artifactID)
        XCTAssertEqual(result.policyChecksum, policy.policyChecksum)
        XCTAssertEqual(result.artifactSHA256, validArtifactSHA)
        XCTAssertEqual(result.observedTopLevelJSONFields, allowedFields.sorted())
        XCTAssertEqual(
            result.contentValidationChecksum,
            ReadinessAssessmentArtifactContentValidationResult.stableContentValidationChecksum(
                artifactID: artifactID,
                policyVersion: policyVersion,
                policyChecksum: policy.policyChecksum,
                artifactSHA256: validArtifactSHA,
                observedTopLevelJSONFields: allowedFields.sorted(),
                validatedAt: validatedAt
            )
        )
        XCTAssertFalse(result.productionTradingEnabledByDefault)
        XCTAssertFalse(result.productionCutoverAuthorized)
        XCTAssertFalse(result.productionSecretRead)
        XCTAssertFalse(result.productionEndpointConnected)
        XCTAssertFalse(result.brokerEndpointConnected)
        XCTAssertFalse(result.productionOrderSubmitted)
        XCTAssertFalse(result.realOrderSubmissionEnabled)
        XCTAssertFalse(result.testnetOrderSubmissionAllowed)
        XCTAssertFalse(result.testnetOrderRoutingAllowed)

        var rejectionIndex = 0
        func rejected(_ payload: String, expected: ReadinessAssessmentRegistryStoreError = .boundaryDrift("artifactContentPolicy:rejectedContent")) throws {
            rejectionIndex += 1
            let data = Data(payload.utf8)
            let manifest = try ReadinessAssessmentManifestV2(
                assessmentID: Identifier.constant("gh-957-rejected-assessment-\(rejectionIndex)"),
                generationID: Identifier.constant("gh-957-rejected-generation"),
                sourceRunIDs: [Identifier.constant("gh-957-source-run")],
                sourceCommit: "6e6f59382546419cf4e04c24635815d44a72a008",
                artifactContentType: .jsonEvidence,
                artifactSHA256: try ProductionReadinessArtifactStore.canonicalJSONSHA256Checksum(for: data),
                artifactBytes: data.count,
                createdAt: Date(timeIntervalSince1970: 1_812_300_000),
                producerVersion: "mtpro-v0.12.0-gh957"
            )
            XCTAssertThrowsError(
                try store.validateArtifactContent(
                    data: data,
                    manifest: manifest,
                    policy: policy,
                    validatedAt: validatedAt
                )
            ) { error in
                XCTAssertEqual(error as? ReadinessAssessmentRegistryStoreError, expected)
            }
        }

        try rejected(#"{"artifactID":"gh-957-redacted-artifact","noOrderPayload":true,"noSecretValue":false,"policyVersion":"policy-v0.12.0-006","productionCutoverAuthorized":false,"redactionProof":false,"secret":"raw-secret"}"#)
        try rejected(#"{"artifactID":"gh-957-redacted-artifact","listenKey":"raw-listen-key","noOrderPayload":true,"noSecretValue":true,"policyVersion":"policy-v0.12.0-006","productionCutoverAuthorized":false,"redactionProof":false}"#)
        try rejected(#"{"artifactID":"gh-957-redacted-artifact","noOrderPayload":false,"noSecretValue":true,"policyVersion":"policy-v0.12.0-006","productionCutoverAuthorized":false,"quantity":"1.0","redactionProof":false,"side":"BUY","type":"MARKET"}"#)
        try rejected(#"{"artifactID":"gh-957-redacted-artifact","endpointResponse":{"balances":[],"serverTime":1812300000},"noOrderPayload":true,"noSecretValue":true,"policyVersion":"policy-v0.12.0-006","productionCutoverAuthorized":false,"redactionProof":false,"url":"https://api.binance.com/api/v3/account"}"#)
        try rejected(#"{"artifactID":"gh-957-redacted-artifact","noOrderPayload":true,"noSecretValue":true,"policyVersion":"policy-v0.12.0-006","productionCutoverAuthorized":false,"redactionProof":true,"unexpectedField":true}"#)
        try rejected(#"{"artifactID":"gh-957-redacted-artifact","noSecretValue":true,"policyVersion":"policy-v0.12.0-006","productionCutoverAuthorized":false,"redactionProof":true}"#)

        let mismatchedManifest = try ReadinessAssessmentManifestV2(
            assessmentID: Identifier.constant("gh-957-mismatched-assessment"),
            generationID: Identifier.constant("gh-957-generation-2"),
            sourceRunIDs: [Identifier.constant("gh-957-source-run")],
            sourceCommit: "6e6f59382546419cf4e04c24635815d44a72a008",
            artifactContentType: .jsonEvidence,
            artifactSHA256: "sha256:\(String(repeating: "b", count: 64))",
            artifactBytes: validData.count,
            createdAt: Date(timeIntervalSince1970: 1_812_300_000),
            producerVersion: "mtpro-v0.12.0-gh957"
        )
        XCTAssertThrowsError(
            try store.validateArtifactContent(
                data: validData,
                manifest: mismatchedManifest,
                policy: policy,
                validatedAt: validatedAt
            )
        ) { error in
            XCTAssertEqual(
                error as? ReadinessAssessmentRegistryStoreError,
                .boundaryDrift("artifactContentPolicy:artifactSHA256Mismatch")
            )
        }
    }

    func testGH958ImmutableReadinessBundleSnapshotRequiresNewGenerationOnChange() throws {
        // 测试场景：GH-958 在 artifact content-policy 之后生成 reviewable readiness bundle。
        // 一旦 bundle 进入 in-review，同一 generation 禁止原地修改；输入变化必须写入新 generation。
        XCTAssertTrue(
            ReadinessAssessmentRegistryStoreAnchors.validationAnchors.contains(
                "GH-958-VERIFY-V0120-IMMUTABLE-READINESS-BUNDLE-SNAPSHOT"
            )
        )
        XCTAssertTrue(
            ReadinessAssessmentRegistryStoreAnchors.validationAnchors.contains(
                "V0120-007-NEW-GENERATION-ON-CHANGE"
            )
        )
        XCTAssertEqual(ReadinessAssessmentBundleV2ReviewState.allCases.map(\.rawValue), ["draft", "in-review"])

        let repositoryRoot = URL(fileURLWithPath: FileManager.default.currentDirectoryPath, isDirectory: true)
        func read(_ relativePath: String) throws -> String {
            try String(contentsOf: repositoryRoot.appendingPathComponent(relativePath), encoding: .utf8)
        }

        let root = FileManager.default.temporaryDirectory
            .appendingPathComponent("MTPRO-GH958-ImmutableBundle-\(UUID().uuidString)", isDirectory: true)
        addTeardownBlock {
            try? FileManager.default.removeItem(at: root)
        }

        let store = ReadinessAssessmentRegistryStore(storageRootURL: root)
        let assessmentID = Identifier.constant("gh-958-assessment")
        let sourceCommit = "0517bf8afdd4ab17d6370eb00856abd2833db33f"
        let createdAt = Date(timeIntervalSince1970: 1_812_400_000)

        func artifactSnapshot(_ id: String, hex: Character, pathGeneration: String) throws -> ReadinessAssessmentBundleV2ArtifactSnapshot {
            let checksum = "sha256:\(String(repeating: String(hex), count: 64))"
            return try ReadinessAssessmentBundleV2ArtifactSnapshot(
                artifactID: Identifier.constant(id),
                manifestChecksum: checksum,
                artifactSHA256: checksum,
                contentValidationChecksum: checksum,
                artifactPath: ".local/mtpro/readiness/assessments/gh-958-assessment/generations/\(pathGeneration)/artifacts/\(id).json"
            )
        }

        let generation1 = Identifier.constant("gh-958-generation-1")
        let bundle1 = try ReadinessAssessmentBundleV2(
            assessmentID: assessmentID,
            generationID: generation1,
            reviewState: .inReview,
            sourceRunIDs: [Identifier.constant("gh-958-run-a"), Identifier.constant("gh-958-run-b")],
            sourceCommit: sourceCommit,
            artifactSnapshots: [
                artifactSnapshot("gh-958-redacted-artifact-a", hex: "a", pathGeneration: generation1.rawValue)
            ],
            createdAt: createdAt,
            producerVersion: "mtpro-v0.12.0-gh958"
        )
        XCTAssertTrue(bundle1.bundleHeld)
        XCTAssertEqual(
            bundle1.bundlePath,
            ".local/mtpro/readiness/assessments/gh-958-assessment/generations/gh-958-generation-1/readiness-bundle-v2.json"
        )
        XCTAssertEqual(
            bundle1.manifestPath,
            ".local/mtpro/readiness/assessments/gh-958-assessment/generations/gh-958-generation-1/readiness-bundle-v2.manifest.json"
        )
        XCTAssertFalse(bundle1.productionCutoverAuthorized)
        XCTAssertFalse(bundle1.productionSecretRead)
        XCTAssertFalse(bundle1.productionEndpointConnected)
        XCTAssertFalse(bundle1.brokerEndpointConnected)
        XCTAssertFalse(bundle1.productionOrderSubmitted)

        let write1 = try store.writeReadinessBundleV2ReviewSnapshot(bundle1)
        XCTAssertEqual(write1.bundle, bundle1)
        XCTAssertTrue(write1.manifest.manifestHeld)
        XCTAssertEqual(write1.manifest.bundleChecksum, bundle1.bundleChecksum)
        XCTAssertTrue(write1.manifest.bundleJSONSHA256.hasPrefix("sha256:"))
        XCTAssertEqual(write1.manifest.bundleJSONSHA256.dropFirst("sha256:".count).count, 64)
        XCTAssertGreaterThan(write1.manifest.bundleBytes, 0)
        XCTAssertEqual(try store.readReadinessBundleV2(assessmentID: assessmentID, generationID: generation1), bundle1)
        XCTAssertEqual(try store.readReadinessBundleV2Manifest(assessmentID: assessmentID, generationID: generation1), write1.manifest)

        XCTAssertThrowsError(
            try store.writeReadinessBundleV2ReviewSnapshot(bundle1)
        ) { error in
            XCTAssertEqual(error as? ReadinessAssessmentRegistryStoreError, .boundaryDrift("readinessBundleV2:generationImmutable"))
        }

        let changedSameGeneration = try ReadinessAssessmentBundleV2(
            assessmentID: assessmentID,
            generationID: generation1,
            reviewState: .inReview,
            sourceRunIDs: [Identifier.constant("gh-958-run-a"), Identifier.constant("gh-958-run-b")],
            sourceCommit: sourceCommit,
            artifactSnapshots: [
                artifactSnapshot("gh-958-redacted-artifact-a", hex: "a", pathGeneration: generation1.rawValue),
                artifactSnapshot("gh-958-redacted-artifact-b", hex: "b", pathGeneration: generation1.rawValue)
            ],
            createdAt: createdAt.addingTimeInterval(60),
            producerVersion: "mtpro-v0.12.0-gh958"
        )
        XCTAssertNotEqual(changedSameGeneration.bundleChecksum, bundle1.bundleChecksum)
        XCTAssertThrowsError(
            try store.writeReadinessBundleV2ReviewSnapshot(changedSameGeneration)
        ) { error in
            XCTAssertEqual(error as? ReadinessAssessmentRegistryStoreError, .boundaryDrift("readinessBundleV2:generationImmutable"))
        }

        let generation2 = Identifier.constant("gh-958-generation-2")
        let bundle2 = try ReadinessAssessmentBundleV2(
            assessmentID: assessmentID,
            generationID: generation2,
            reviewState: .inReview,
            sourceRunIDs: [Identifier.constant("gh-958-run-a"), Identifier.constant("gh-958-run-b")],
            sourceCommit: sourceCommit,
            artifactSnapshots: [
                artifactSnapshot("gh-958-redacted-artifact-a", hex: "a", pathGeneration: generation2.rawValue),
                artifactSnapshot("gh-958-redacted-artifact-b", hex: "b", pathGeneration: generation2.rawValue)
            ],
            createdAt: createdAt.addingTimeInterval(120),
            producerVersion: "mtpro-v0.12.0-gh958"
        )
        let write2 = try store.writeReadinessBundleV2ReviewSnapshot(bundle2)
        XCTAssertNotEqual(bundle2.generationID, bundle1.generationID)
        XCTAssertNotEqual(bundle2.bundlePath, bundle1.bundlePath)
        XCTAssertNotEqual(bundle2.bundleChecksum, bundle1.bundleChecksum)
        XCTAssertEqual(try store.readReadinessBundleV2(assessmentID: assessmentID, generationID: generation2), bundle2)
        XCTAssertEqual(try store.readReadinessBundleV2Manifest(assessmentID: assessmentID, generationID: generation2), write2.manifest)
        XCTAssertNotEqual(write2.manifest.bundleJSONSHA256, write1.manifest.bundleJSONSHA256)
        XCTAssertNotEqual(write2.manifest.manifestChecksum, write1.manifest.manifestChecksum)

        let draft = try ReadinessAssessmentBundleV2(
            assessmentID: Identifier.constant("gh-958-draft-assessment"),
            generationID: Identifier.constant("gh-958-draft-generation"),
            reviewState: .draft,
            sourceRunIDs: [Identifier.constant("gh-958-run-a")],
            sourceCommit: sourceCommit,
            artifactSnapshots: [
                artifactSnapshot("gh-958-draft-artifact", hex: "c", pathGeneration: "gh-958-draft-generation")
            ],
            createdAt: createdAt,
            producerVersion: "mtpro-v0.12.0-gh958"
        )
        XCTAssertThrowsError(
            try store.writeReadinessBundleV2ReviewSnapshot(draft)
        ) { error in
            XCTAssertEqual(error as? ReadinessAssessmentRegistryStoreError, .boundaryDrift("readinessBundleV2:reviewStateMustBeInReview"))
        }

        XCTAssertThrowsError(
            try ReadinessAssessmentBundleV2(
                assessmentID: Identifier.constant("gh-958-bad-assessment"),
                generationID: Identifier.constant("gh-958-bad-generation"),
                reviewState: .inReview,
                sourceRunIDs: [Identifier.constant("gh-958-run-a")],
                sourceCommit: sourceCommit,
                artifactSnapshots: [
                    artifactSnapshot("gh-958-bad-artifact", hex: "d", pathGeneration: "gh-958-bad-generation")
                ],
                createdAt: createdAt,
                producerVersion: "mtpro-v0.12.0-gh958",
                productionCutoverAuthorized: true
            )
        ) { error in
            XCTAssertEqual(error as? ReadinessAssessmentRegistryStoreError, .boundaryDrift("readinessBundleV2"))
        }

        let source = try read("Sources/ExecutionClient/FutureGate/ReleaseV0120ReadinessAssessmentRegistryStore.swift")
        let contract = try read("docs/contracts/release-v0.12.0-readiness-assessment-session-contract.md")
        let verifier = try read("checks/verify-v0.12.0.sh")
        let readinessScript = try read("checks/automation-readiness.sh")
        let readiness = try read("docs/automation/automation-readiness.md")
        let validationPlan = try read("docs/validation/validation-plan.md")
        let tradingMatrix = try read("docs/validation/trading-validation-matrix.md")
        let latest = try read("docs/validation/latest-verification-summary.md")

        let expectedAnchors = [
            "GH-958-VERIFY-V0120-IMMUTABLE-READINESS-BUNDLE-SNAPSHOT",
            "TVM-RELEASE-V0120-IMMUTABLE-READINESS-BUNDLE-SNAPSHOT",
            "V0120-007-IMMUTABLE-READINESS-BUNDLE-SNAPSHOT",
            "V0120-007-READINESS-BUNDLE-V2-JSON",
            "V0120-007-READINESS-BUNDLE-V2-MANIFEST-JSON",
            "V0120-007-REVIEW-SNAPSHOT-IMMUTABLE",
            "V0120-007-NEW-GENERATION-ON-CHANGE",
            "V0120-007-BUNDLE-MANIFEST-CHECKSUM",
            "V0120-007-NO-PRODUCTION-CUTOVER"
        ]

