            "changeRequiresNewGeneration"
        ] {
            XCTAssertTrue(source.contains(expectedSource), "\(expectedSource) must stay represented in GH-958 source")
        }
    }

    func testGH959KillSwitchNoTradeTrustworthyObservationsFailClosed() throws {
        // 测试场景：GH-959 将 kill switch / no-trade 的 freshness 和 review state 改为从
        // 本地 source artifact evidence 派生，拒绝 caller 直接声明 fresh / reviewed。
        let repositoryRoot = URL(fileURLWithPath: FileManager.default.currentDirectoryPath, isDirectory: true)
        func read(_ relativePath: String) throws -> String {
            try String(contentsOf: repositoryRoot.appendingPathComponent(relativePath), encoding: .utf8)
        }

        let evaluatedAt = Date(timeIntervalSince1970: 1_812_600_000)
        let sourceArtifact = ".local/mtpro/readiness/assessments/gh-959/artifacts/kill-switch-no-trade.json"
        let sourceChecksum = "sha256:\(String(repeating: "c", count: 64))"
        let sourceRunID = Identifier.constant("gh-959-source-run")

        func snapshot(
            _ name: String,
            state: ReleaseV0100KillSwitchNoTradeReadinessState = .inactive,
            observedAt: Date? = nil,
            expiresAt: Date? = nil,
            reviewedAt: Date? = nil,
            reviewedBy: String? = "Codex",
            expectedArtifact: String? = nil,
            expectedChecksum: String? = nil,
            expectedRunID: Identifier? = nil
        ) throws -> ReleaseV0110KillSwitchNoTradeReadinessSnapshot {
            let resolvedObservedAt = observedAt ?? evaluatedAt.addingTimeInterval(-60)
            let resolvedExpiresAt = expiresAt ?? evaluatedAt.addingTimeInterval(300)
            return try ReleaseV0110KillSwitchNoTradeReadinessSnapshot(
                name: name,
                state: state,
                observedAt: resolvedObservedAt,
                expiresAt: resolvedExpiresAt,
                reviewedAt: reviewedAt ?? evaluatedAt.addingTimeInterval(-30),
                reviewedBy: reviewedBy,
                sourceArtifact: sourceArtifact,
                sourceChecksum: sourceChecksum,
                sourceRunID: sourceRunID,
                expectedSourceArtifact: expectedArtifact ?? sourceArtifact,
                expectedSourceChecksum: expectedChecksum ?? sourceChecksum,
                expectedSourceRunID: expectedRunID ?? sourceRunID,
                evaluatedAt: evaluatedAt
            )
        }

        let freshReviewed = try snapshot("kill-switch")
        XCTAssertEqual(freshReviewed.observedAt, evaluatedAt.addingTimeInterval(-60))
        XCTAssertEqual(freshReviewed.expiresAt, evaluatedAt.addingTimeInterval(300))
        XCTAssertEqual(freshReviewed.reviewedAt, evaluatedAt.addingTimeInterval(-30))
        XCTAssertEqual(freshReviewed.reviewedBy, "Codex")
        XCTAssertEqual(freshReviewed.sourceArtifact, sourceArtifact)
        XCTAssertEqual(freshReviewed.sourceChecksum, sourceChecksum)
        XCTAssertEqual(freshReviewed.sourceRunID, sourceRunID)
        XCTAssertEqual(freshReviewed.freshnessState, .fresh)
        XCTAssertEqual(freshReviewed.reviewState, .reviewed)
        XCTAssertTrue(freshReviewed.approvalRequestEligible)

        let eligible = try ReleaseV0110KillSwitchNoTradeReadinessStateModel(
            issueID: Identifier.constant("GH-922"),
            upstreamIssueIDs: [Identifier.constant("GH-913")],
            killSwitchSnapshot: try snapshot("kill-switch"),
            noTradeSnapshot: try snapshot("no-trade")
        )
        XCTAssertTrue(eligible.approvalRequestEligible)
        XCTAssertEqual(eligible.approvalRequestEligibility, .eligibleForApprovalRequest)
        XCTAssertTrue(eligible.productionCutoverBlocked)
        XCTAssertFalse(eligible.cutoverAuthorized)
        XCTAssertFalse(eligible.orderSubmissionEnabled)
        XCTAssertFalse(eligible.testnetOrderSubmissionEnabled)
        XCTAssertFalse(eligible.productionEndpointConnectionEnabled)
        XCTAssertFalse(eligible.productionBrokerConnectionEnabled)
        XCTAssertFalse(eligible.productionSecretValueRead)

        let expired = try snapshot(
            "kill-switch",
            expiresAt: evaluatedAt.addingTimeInterval(-1)
        )
        XCTAssertEqual(expired.freshnessState, .stale)
        XCTAssertTrue(expired.failClosed)

        let futureObservation = try snapshot(
            "kill-switch",
            observedAt: evaluatedAt.addingTimeInterval(60),
            expiresAt: evaluatedAt.addingTimeInterval(300),
            reviewedAt: evaluatedAt.addingTimeInterval(-30)
        )
        XCTAssertEqual(futureObservation.freshnessState, .unknown)
        XCTAssertEqual(futureObservation.reviewState, .unknown)
        XCTAssertTrue(futureObservation.failClosed)

        let unreviewed = try snapshot(
            "kill-switch",
            reviewedAt: nil,
            reviewedBy: nil
        )
        XCTAssertEqual(unreviewed.freshnessState, .fresh)
        XCTAssertEqual(unreviewed.reviewState, .pending)
        XCTAssertTrue(unreviewed.failClosed)

        let mismatchedArtifact = try snapshot(
            "kill-switch",
            expectedArtifact: ".local/mtpro/readiness/assessments/gh-959/artifacts/mismatch.json"
        )
        XCTAssertEqual(mismatchedArtifact.freshnessState, .unavailable)
        XCTAssertEqual(mismatchedArtifact.reviewState, .unavailable)
        XCTAssertTrue(mismatchedArtifact.failClosed)

        let mismatchedChecksum = try snapshot(
            "kill-switch",
            expectedChecksum: "sha256:\(String(repeating: "d", count: 64))"
        )
        XCTAssertEqual(mismatchedChecksum.freshnessState, .unavailable)
        XCTAssertEqual(mismatchedChecksum.reviewState, .unavailable)
        XCTAssertTrue(mismatchedChecksum.failClosed)

        let mismatchedRun = try snapshot(
            "kill-switch",
            expectedRunID: Identifier.constant("gh-959-mismatch-source-run")
        )
        XCTAssertEqual(mismatchedRun.freshnessState, .unavailable)
        XCTAssertEqual(mismatchedRun.reviewState, .unavailable)
        XCTAssertTrue(mismatchedRun.failClosed)

        let staleModel = try ReleaseV0110KillSwitchNoTradeReadinessStateModel(
            killSwitchSnapshot: expired,
            noTradeSnapshot: try snapshot("no-trade")
        )
        XCTAssertTrue(staleModel.failClosed)
        XCTAssertFalse(staleModel.approvalRequestEligible)
        XCTAssertEqual(staleModel.approvalRequestEligibility, .blocked)
        XCTAssertTrue(staleModel.productionCutoverBlocked)
        XCTAssertFalse(staleModel.cutoverAuthorized)
        XCTAssertFalse(staleModel.orderSubmissionEnabled)

        let source = try read("Sources/ExecutionClient/FutureGate/ReleaseV0100KillSwitchNoTradeReadinessGate.swift")
        let contract = try read("docs/contracts/release-v0.12.0-readiness-assessment-session-contract.md")
        let verifier = try read("checks/verify-v0.12.0.sh")
        let readinessScript = try read("checks/automation-readiness.sh")
        let readiness = try read("docs/automation/automation-readiness.md")
        let validationPlan = try read("docs/validation/validation-plan.md")
        let tradingMatrix = try read("docs/validation/trading-validation-matrix.md")
        let latest = try read("docs/validation/latest-verification-summary.md")

        let expectedAnchors = [
            "GH-959-VERIFY-V0120-KILL-SWITCH-NO-TRADE-TRUSTWORTHY-OBSERVATIONS",
            "TVM-RELEASE-V0120-KILL-SWITCH-NO-TRADE-TRUSTWORTHY-OBSERVATIONS",
            "V0120-008-KILL-SWITCH-NO-TRADE-TRUSTWORTHY-OBSERVATIONS",
            "V0120-008-OBSERVED-EXPIRES-REVIEWED-SOURCE-EVIDENCE",
            "V0120-008-DERIVED-FRESHNESS-AND-REVIEW-STATE",
            "V0120-008-STALE-UNREVIEWED-MISMATCH-FAIL-CLOSED",
            "V0120-008-APPROVAL-REQUEST-ONLY-NO-CUTOVER",
            "V0120-008-NO-PRODUCTION-CUTOVER"
        ]
        XCTAssertEqual(ReleaseV0120KillSwitchNoTradeTrustworthyObservationAnchors.validationAnchors, expectedAnchors)

        for anchor in expectedAnchors {
            XCTAssertTrue(source.contains(anchor), "\(anchor) must stay in kill switch / no-trade source")
            XCTAssertTrue(contract.contains(anchor), "\(anchor) must stay in v0.12.0 contract")
            XCTAssertTrue(verifier.contains(anchor), "\(anchor) must stay in v0.12.0 verifier")
            XCTAssertTrue(readinessScript.contains(anchor), "\(anchor) must stay in automation readiness")
            XCTAssertTrue(readiness.contains(anchor), "\(anchor) must stay in readiness docs")
            XCTAssertTrue(validationPlan.contains(anchor), "\(anchor) must stay in validation plan")
            XCTAssertTrue(tradingMatrix.contains(anchor), "\(anchor) must stay in trading matrix")
            XCTAssertTrue(latest.contains(anchor), "\(anchor) must stay in latest summary")
        }

        for expectedSource in [
            "observedAt",
            "expiresAt",
            "reviewedAt",
            "reviewedBy",
            "sourceArtifact",
            "sourceChecksum",
            "sourceRunID",
            "expectedSourceArtifact",
            "expectedSourceChecksum",
            "expectedSourceRunID",
            "deriveFreshnessState",
            "deriveReviewState",
            "ProductionReadinessArtifactDescriptor.isSafeRelativePath",
            "ReadinessAssessmentManifestV2.isValidSHA256Checksum"
        ] {
            XCTAssertTrue(source.contains(expectedSource), "\(expectedSource) must stay represented in GH-959 source")
        }
    }

    func testGH917ReadinessBundleValidationClassifiesRequiredArtifactsPolicyAndChecksum() throws {
        XCTAssertEqual(ProductionReadinessBundleValidationAnchors.validationAnchors, [
            "GH-917-VERIFY-V0110-READINESS-BUNDLE-VALIDATION",
            "TVM-RELEASE-V0110-READINESS-BUNDLE-VALIDATION",
            "V0110-005-READINESS-BUNDLE-VALIDATION",
            "V0110-005-REQUIRED-ARTIFACT-SET",
            "V0110-005-BUNDLE-VALIDATION-STATES",
            "V0110-005-POLICY-VERSION-BLOCKED",
            "V0110-005-CHECKSUM-MISMATCH-STATE",
            "V0110-005-NO-PRODUCTION-CUTOVER"
        ])
        XCTAssertEqual(
            ProductionReadinessBundleValidationState.allCases.map(\.rawValue),
            ["not-evaluated", "valid", "blocked", "stale", "missing", "invalid", "checksum-mismatch"]
        )

        let riskID = Identifier.constant("gh-917-risk-policy")
        let secretID = Identifier.constant("gh-917-secret-readiness")
        let requiredArtifactIDs = [riskID, secretID]
        let policyVersion = "policy-v0.11.0-003"
        let now = Date(timeIntervalSince1970: 1_800_030_000)
        let notEvaluated = try ProductionReadinessArtifactStore.notEvaluatedReadinessBundleValidation(
            requiredPolicyVersion: policyVersion,
            requiredArtifactIDs: requiredArtifactIDs,
            evaluatedAt: now
        )
        XCTAssertEqual(notEvaluated.state, .notEvaluated)
        XCTAssertTrue(notEvaluated.resultHeld)
        XCTAssertFalse(notEvaluated.productionCutoverAuthorized)

        let evidenceRoot = FileManager.default.temporaryDirectory.appendingPathComponent(
            "MTPRO-GH917-BundleValidation-\(UUID().uuidString)",
            isDirectory: true
        )
        addTeardownBlock {
            try? FileManager.default.removeItem(at: evidenceRoot)
        }

        let store = try ProductionReadinessArtifactStore(evidenceRootURL: evidenceRoot)
        let riskDescriptor = try ProductionReadinessArtifactDescriptor(
            artifactID: riskID,
            relativePath: "artifacts/risk-policy.json",
            artifactType: .jsonEvidence,
            staleAfterSeconds: 120
        )
        let secretDescriptor = try ProductionReadinessArtifactDescriptor(
            artifactID: secretID,
            relativePath: "artifacts/secret-readiness.json",
            artifactType: .jsonEvidence,
            staleAfterSeconds: 120
        )
        let manifestDescriptor = try ProductionReadinessArtifactDescriptor(
            artifactID: Identifier.constant("gh-917-readiness-manifest"),
            relativePath: "manifest/readiness-manifest.json",
            artifactType: .jsonEvidence
        )
        let riskPayload = #"{"artifactID":"gh-917-risk","policyVersion":"policy-v0.11.0-003","productionCutoverAuthorized":false,"productionTradingEnabledByDefault":false}"#
        let riskDriftPayload = #"{"artifactID":"gh-917-fail","policyVersion":"policy-v0.11.0-003","productionCutoverAuthorized":false,"productionTradingEnabledByDefault":false}"#
        XCTAssertEqual(Data(riskPayload.utf8).count, Data(riskDriftPayload.utf8).count)
        let secretPayload = #"{"artifactID":"gh-917-secret","policyVersion":"policy-v0.11.0-003","productionCutoverAuthorized":false,"productionSecretRead":false}"#

        func writeArtifactsAndManifest() throws {
            _ = try store.writeStringArtifact(
                descriptor: riskDescriptor,
                string: riskPayload,
                modifiedAt: now
            )
            _ = try store.writeStringArtifact(
                descriptor: secretDescriptor,
                string: secretPayload,
                modifiedAt: now
            )
            _ = try store.writeReadinessManifest(
                manifestID: manifestDescriptor.artifactID,
                manifestRelativePath: manifestDescriptor.relativePath,
                descriptors: [riskDescriptor, secretDescriptor],
                policyVersion: policyVersion,
                generatedAt: now.addingTimeInterval(1),
                now: now
            )
        }

        try writeArtifactsAndManifest()
        let valid = try store.validateReadinessBundle(
            manifestDescriptor: manifestDescriptor,
            requiredPolicyVersion: policyVersion,
            requiredArtifactIDs: requiredArtifactIDs,
            now: now.addingTimeInterval(10)
        )
        XCTAssertEqual(valid.state, .valid)
        XCTAssertTrue(valid.bundleValidHeld)
        XCTAssertEqual(valid.requiredArtifactIDs.map(\.rawValue), requiredArtifactIDs.map(\.rawValue))
        XCTAssertEqual(valid.manifestArtifactIDs.map(\.rawValue), requiredArtifactIDs.map(\.rawValue))
        XCTAssertFalse(valid.productionCutoverAuthorized)
        XCTAssertFalse(valid.productionTradingEnabledByDefault)
        XCTAssertFalse(valid.productionEndpointConnected)
        XCTAssertFalse(valid.productionOrderSubmitted)

        let missingRequiredID = Identifier.constant("gh-917-required-but-absent")
        let missingRequired = try store.validateReadinessBundle(
            manifestDescriptor: manifestDescriptor,
            requiredPolicyVersion: policyVersion,
            requiredArtifactIDs: requiredArtifactIDs + [missingRequiredID],
            now: now.addingTimeInterval(10)
        )
        XCTAssertEqual(missingRequired.state, .missing)
        XCTAssertEqual(missingRequired.missingRequiredArtifactIDs.map(\.rawValue), [missingRequiredID.rawValue])

        let blocked = try store.validateReadinessBundle(
            manifestDescriptor: manifestDescriptor,
            requiredPolicyVersion: "policy-v0.11.0-other",
            requiredArtifactIDs: requiredArtifactIDs,
            now: now.addingTimeInterval(10)
        )
        XCTAssertEqual(blocked.state, .blocked)
        XCTAssertTrue(blocked.stateReason.contains("policy version"))

        let stale = try store.validateReadinessBundle(
            manifestDescriptor: manifestDescriptor,
            requiredPolicyVersion: policyVersion,
            requiredArtifactIDs: requiredArtifactIDs,
            now: now.addingTimeInterval(240)
        )
        XCTAssertEqual(stale.state, .stale)

        let manifestURL = try store.artifactURL(for: manifestDescriptor)
        try Data("{\"evidenceExists\":true}".utf8).write(to: manifestURL, options: .atomic)
        try FileManager.default.setAttributes([.modificationDate: now], ofItemAtPath: manifestURL.path)
        let invalid = try store.validateReadinessBundle(
            manifestDescriptor: manifestDescriptor,
            requiredPolicyVersion: policyVersion,
            requiredArtifactIDs: requiredArtifactIDs,
            now: now.addingTimeInterval(10)
        )
        XCTAssertEqual(invalid.state, .invalid)

        try writeArtifactsAndManifest()
        try FileManager.default.removeItem(at: try store.artifactURL(for: secretDescriptor))
        let missingArtifact = try store.validateReadinessBundle(
            manifestDescriptor: manifestDescriptor,
            requiredPolicyVersion: policyVersion,
            requiredArtifactIDs: requiredArtifactIDs,
            now: now.addingTimeInterval(10)
        )
        XCTAssertEqual(missingArtifact.state, .missing)
        XCTAssertEqual(missingArtifact.missingRequiredArtifactIDs.map(\.rawValue), [secretID.rawValue])

        try writeArtifactsAndManifest()
        _ = try store.writeStringArtifact(
            descriptor: riskDescriptor,
            string: riskDriftPayload,
            modifiedAt: now
        )
        let checksumMismatch = try store.validateReadinessBundle(
            manifestDescriptor: manifestDescriptor,
            requiredPolicyVersion: policyVersion,
            requiredArtifactIDs: requiredArtifactIDs,
            now: now.addingTimeInterval(10)
        )
        XCTAssertEqual(checksumMismatch.state, .checksumMismatch)
        XCTAssertTrue(checksumMismatch.stateReason.contains("checksum mismatch"))
    }

    func testGH918ShadowDryRunParityRunnerBuildsArtifactFromLocalRunEvidence() throws {
        let repositoryRoot = URL(fileURLWithPath: FileManager.default.currentDirectoryPath, isDirectory: true)
        func read(_ relativePath: String) throws -> String {
            try String(contentsOf: repositoryRoot.appendingPathComponent(relativePath), encoding: .utf8)
        }

        XCTAssertEqual(ProductionReadinessShadowDryRunParityRunnerAnchors.validationAnchors, [
            "GH-918-VERIFY-V0110-SHADOW-DRY-RUN-PARITY-RUNNER",
            "TVM-RELEASE-V0110-SHADOW-DRY-RUN-PARITY-RUNNER",
            "V0110-006-SHADOW-DRY-RUN-PARITY-RUNNER",
            "V0110-006-LOCAL-RUN-EVIDENCE",
            "V0110-006-SHADOW-PARITY-ARTIFACT",
            "V0110-006-MISSING-INCOMPLETE-BLOCKED",
            "V0110-006-NO-PRODUCTION-ENDPOINT-SECRET-ORDER"
        ])

        let evidenceRoot = FileManager.default.temporaryDirectory.appendingPathComponent(
            "MTPRO-GH918-ShadowDryRunParity-\(UUID().uuidString)",
            isDirectory: true
        )
        addTeardownBlock {
            try? FileManager.default.removeItem(at: evidenceRoot)
        }

        let store = try ProductionReadinessArtifactStore(evidenceRootURL: evidenceRoot)
        let runID = Identifier.constant("gh-918-local-run")
        let policyVersion = "policy-v0.11.0-004"
        let now = Date(timeIntervalSince1970: 1_800_040_000)
        let inputs = try ProductionReadinessShadowDryRunParityEvidenceInput.defaultInputs(
            runID: runID,
            staleAfterSeconds: 120
        )
        let artifactDescriptor = try ProductionReadinessArtifactDescriptor(
            artifactID: Identifier.constant("gh-918-shadow-dry-run-parity"),
            relativePath: "runs/\(runID.rawValue)/shadow_dry_run_parity.json",
            artifactType: .jsonEvidence,
            staleAfterSeconds: 120
        )
        let manifestDescriptor = try ProductionReadinessArtifactDescriptor(
            artifactID: Identifier.constant("gh-918-shadow-dry-run-parity-manifest"),
            relativePath: "runs/\(runID.rawValue)/shadow_dry_run_parity_manifest.json",
            artifactType: .jsonEvidence
        )

        func payload(for kind: ProductionReadinessShadowDryRunParityEvidenceKind) -> String {
            """
            {
              "artifactID": "gh-918-\(kind.artifactIDComponent)",
              "localRunEvidenceKind": "\(kind.rawValue)",
              "runID": "\(runID.rawValue)",
              "policyVersion": "\(policyVersion)",
              "sequence": "\(kind.artifactIDComponent)",
              "derivedFromLocalRunEvidence": true,
              "productionTradingEnabledByDefault": false,
              "productionCutoverAuthorized": false,
              "productionSecretRead": false,
              "productionEndpointConnected": false,
              "brokerEndpointConnected": false,
              "productionOrderSubmitted": false,
              "testnetOrderSubmissionAllowed": false
            }
            """
        }

        for input in inputs {
            _ = try store.writeStringArtifact(
                descriptor: input.descriptor,
                string: payload(for: input.kind),
                modifiedAt: now
            )
        }
        let expectedChecksums = try inputs.map { input in
            try ProductionReadinessArtifactStore.canonicalJSONSHA256Checksum(for: Data(payload(for: input.kind).utf8))
        }

        let valid = try store.writeShadowDryRunParityArtifact(
            runID: runID,
            policyVersion: policyVersion,
            evidenceInputs: inputs,
            artifactDescriptor: artifactDescriptor,
            manifestDescriptor: manifestDescriptor,
            generatedAt: now.addingTimeInterval(10),
            now: now.addingTimeInterval(10)
        )
        XCTAssertTrue(valid.resultHeld)
        XCTAssertTrue(valid.artifact.artifactHeld)
        XCTAssertEqual(valid.artifact.state, .valid)
        XCTAssertEqual(valid.artifact.sourceEvidence.count, ProductionReadinessShadowDryRunParityEvidenceKind.allCases.count)
        XCTAssertTrue(valid.bundleValidation.bundleValidHeld)
        XCTAssertFalse(valid.artifact.productionCutoverAuthorized)
        XCTAssertFalse(valid.artifact.productionSecretRead)
        XCTAssertFalse(valid.artifact.productionEndpointConnected)
        XCTAssertFalse(valid.artifact.brokerEndpointConnected)
        XCTAssertFalse(valid.artifact.productionOrderSubmitted)
        XCTAssertFalse(valid.artifact.testnetOrderSubmissionAllowed)
        XCTAssertFalse(valid.artifact.referenceOnlyStageConstantsUsed)

        let output = try String(
            contentsOf: store.artifactURL(for: artifactDescriptor),
            encoding: .utf8
        )
        XCTAssertTrue(output.contains("\"derivedFromLocalRunEvidence\":true"))
        XCTAssertTrue(output.contains("\"referenceOnlyStageConstantsUsed\":false"))
        XCTAssertTrue(output.contains("\"state\":\"valid\""))
        XCTAssertTrue(output.contains("events.jsonl"))
        for checksum in expectedChecksums {
            XCTAssertTrue(output.contains(checksum), "\(checksum) must be carried from source evidence")
        }

        try FileManager.default.removeItem(at: try store.artifactURL(for: inputs[0].descriptor))
        let blocked = try store.writeShadowDryRunParityArtifact(
            runID: runID,
            policyVersion: policyVersion,
            evidenceInputs: inputs,
            artifactDescriptor: artifactDescriptor,
            manifestDescriptor: manifestDescriptor,
            generatedAt: now.addingTimeInterval(20),
            now: now.addingTimeInterval(20)
        )
        XCTAssertTrue(blocked.resultHeld)
        XCTAssertEqual(blocked.artifact.state, .blocked)
        XCTAssertEqual(blocked.artifact.missingEvidenceKinds, [.eventsJSONL])
        XCTAssertTrue(blocked.artifact.stateReason.contains("missing local run evidence"))

        _ = try store.writeStringArtifact(
            descriptor: inputs[0].descriptor,
            string: #"{"artifactID":"gh-918-bad-marker","localRunEvidenceKind":"wrong","productionCutoverAuthorized":false}"#,
            modifiedAt: now.addingTimeInterval(25)
        )
        let invalid = try store.writeShadowDryRunParityArtifact(
            runID: runID,
            policyVersion: policyVersion,
            evidenceInputs: inputs,
            artifactDescriptor: artifactDescriptor,
            manifestDescriptor: manifestDescriptor,
            generatedAt: now.addingTimeInterval(30),
            now: now.addingTimeInterval(30)
        )
        XCTAssertTrue(invalid.resultHeld)
        XCTAssertEqual(invalid.artifact.state, .invalid)
        XCTAssertEqual(invalid.artifact.invalidEvidenceKinds, [.eventsJSONL])
        XCTAssertTrue(invalid.artifact.stateReason.contains("invalid or incomplete local run evidence"))

        let source = try read("Sources/ExecutionClient/FutureGate/ReleaseV0110ProductionReadinessArtifactStore.swift")
        let contract = try read("docs/contracts/release-v0.11.0-production-readiness-evidence-runtime-contract.md")
        let verifier = try read("checks/verify-v0.11.0.sh")
        let readiness = try read("docs/automation/automation-readiness.md")
        let readinessScript = try read("checks/automation-readiness.sh")
        let validationPlan = try read("docs/validation/validation-plan.md")
        let tradingMatrix = try read("docs/validation/trading-validation-matrix.md")
        let latest = try read("docs/validation/latest-verification-summary.md")

        for anchor in ProductionReadinessShadowDryRunParityRunnerAnchors.validationAnchors {
            XCTAssertTrue(source.contains(anchor), "\(anchor) must stay in Swift source")
            XCTAssertTrue(contract.contains(anchor), "\(anchor) must stay in v0.11.0 contract")
            XCTAssertTrue(verifier.contains(anchor), "\(anchor) must stay in v0.11.0 verifier")
            XCTAssertTrue(readiness.contains(anchor), "\(anchor) must stay in automation readiness docs")
            XCTAssertTrue(readinessScript.contains(anchor), "\(anchor) must stay in automation readiness shell gate")
            XCTAssertTrue(validationPlan.contains(anchor), "\(anchor) must stay in validation plan")
            XCTAssertTrue(tradingMatrix.contains(anchor), "\(anchor) must stay in trading validation matrix")
            XCTAssertTrue(latest.contains(anchor), "\(anchor) must stay in latest verification summary")
        }

        XCTAssertTrue(verifier.contains("testGH918ShadowDryRunParityRunnerBuildsArtifactFromLocalRunEvidence"))
        XCTAssertTrue(readiness.contains("Release v0.11.0 shadow dry-run parity runner anchor"))
        XCTAssertTrue(validationPlan.contains("GH-918 Release v0.11.0 Shadow Dry-run Parity Runner Validation"))
        XCTAssertTrue(tradingMatrix.contains("TVM-RELEASE-V0110-SHADOW-DRY-RUN-PARITY-RUNNER"))
        XCTAssertTrue(latest.contains("Release v0.11.0 Shadow Dry-run Parity Runner Snapshot"))
        XCTAssertTrue(contract.contains("shadow_dry_run_parity.json"))
        XCTAssertTrue(contract.contains("events.jsonl"))
        XCTAssertTrue(contract.contains("derivedFromLocalRunEvidence=true"))
        XCTAssertTrue(contract.contains("referenceOnlyStageConstantsUsed=false"))
        XCTAssertTrue(contract.contains("productionEndpointConnected=false"))
        XCTAssertTrue(contract.contains("productionSecretRead=false"))
        XCTAssertTrue(contract.contains("productionOrderSubmitted=false"))

        for forbidden in [
            "productionTradingEnabledByDefault=true",
            "productionCutoverAuthorized=true",
            "productionSecretRead=true",
            "productionEndpointConnected=true",
            "brokerEndpointConnected=true",
            "productionOrderSubmitted=true",
            "testnetOrderSubmissionAllowed=true",
            "api.binance.com",
            "fapi.binance.com"
        ] {
            XCTAssertFalse(contract.contains(forbidden), "\(forbidden) must stay out of #918 contract")
            XCTAssertFalse(latest.contains(forbidden), "\(forbidden) must stay out of latest summary")
        }
    }

    func testGH961ShadowParityBindsImmutableSourceRunSnapshot() throws {
        let repositoryRoot = URL(fileURLWithPath: FileManager.default.currentDirectoryPath, isDirectory: true)
        func read(_ relativePath: String) throws -> String {
            try String(contentsOf: repositoryRoot.appendingPathComponent(relativePath), encoding: .utf8)
        }

        XCTAssertEqual(ReleaseV0120ShadowParitySourceSnapshotAnchors.validationAnchors, [
            "GH-961-VERIFY-V0120-SHADOW-PARITY-SOURCE-SNAPSHOT",
            "TVM-RELEASE-V0120-SHADOW-PARITY-SOURCE-SNAPSHOT",
            "V0120-010-SHADOW-PARITY-SOURCE-SNAPSHOT",
            "V0120-010-SOURCE-RUN-MANIFEST-CHECKSUM",
            "V0120-010-EVENT-ID-SET-BINDING",
            "V0120-010-RISK-DECISION-ID-BINDING",
            "V0120-010-OMS-DRY-RUN-LIFECYCLE-ID-BINDING",
            "V0120-010-PORTFOLIO-PROJECTION-CHECKSUM-BINDING",
            "V0120-010-RECONCILIATION-CHECKSUM-BINDING",
            "V0120-010-NO-PRODUCTION-CUTOVER"
        ])

        let evidenceRoot = FileManager.default.temporaryDirectory.appendingPathComponent(
            "MTPRO-GH961-ShadowParitySourceSnapshot-\(UUID().uuidString)",
            isDirectory: true
        )
        addTeardownBlock {
            try? FileManager.default.removeItem(at: evidenceRoot)
        }

        let store = try ProductionReadinessArtifactStore(evidenceRootURL: evidenceRoot)
        let runID = Identifier.constant("gh-961-local-run")
        let policyVersion = "policy-v0.12.0-010"
        let now = Date(timeIntervalSince1970: 1_800_120_000)
        let inputs = try ProductionReadinessShadowDryRunParityEvidenceInput.defaultInputs(
            runID: runID,
            staleAfterSeconds: 120
        )
        let artifactDescriptor = try ProductionReadinessArtifactDescriptor(
            artifactID: Identifier.constant("gh-961-shadow-parity-source-snapshot"),
            relativePath: "runs/\(runID.rawValue)/shadow_dry_run_parity.json",
            artifactType: .jsonEvidence,
            staleAfterSeconds: 120
        )
        let manifestDescriptor = try ProductionReadinessArtifactDescriptor(
            artifactID: Identifier.constant("gh-961-shadow-parity-source-snapshot-manifest"),
            relativePath: "runs/\(runID.rawValue)/shadow_dry_run_parity_manifest.json",
            artifactType: .jsonEvidence
        )

        func checksum(_ scalar: String) -> String {
            "sha256:" + String(repeating: scalar, count: 64)
        }

        func snapshot(
            manifest: String = "a",
            eventIDs: [String] = ["event-1", "event-2"],
            riskDecisionIDs: [String] = ["risk-decision-1"],
            omsDryRunLifecycleIDs: [String] = ["oms-dry-run-1"],
            portfolio: String = "b",
            reconciliation: String = "c"
        ) throws -> ReleaseV0120ShadowParitySourceRunSnapshot {
            try ReleaseV0120ShadowParitySourceRunSnapshot(
                runID: runID,
                sourceRunManifestChecksum: checksum(manifest),
                eventIDs: eventIDs.map { Identifier.constant($0) },
                riskDecisionIDs: riskDecisionIDs.map { Identifier.constant($0) },
                omsDryRunLifecycleIDs: omsDryRunLifecycleIDs.map { Identifier.constant($0) },
                portfolioProjectionChecksum: checksum(portfolio),
                reconciliationChecksum: checksum(reconciliation)
            )
        }

        func payload(for kind: ProductionReadinessShadowDryRunParityEvidenceKind) -> String {
            """
            {
              "artifactID": "gh-961-\(kind.artifactIDComponent)",
              "localRunEvidenceKind": "\(kind.rawValue)",
              "runID": "\(runID.rawValue)",
              "policyVersion": "\(policyVersion)",
              "sequence": "\(kind.artifactIDComponent)",
              "derivedFromLocalRunEvidence": true,
              "productionTradingEnabledByDefault": false,
              "productionCutoverAuthorized": false,
              "productionSecretRead": false,
              "productionEndpointConnected": false,
              "brokerEndpointConnected": false,
              "productionOrderSubmitted": false,
              "testnetOrderSubmissionAllowed": false
            }
            """
        }

        for input in inputs {
            _ = try store.writeStringArtifact(
                descriptor: input.descriptor,
                string: payload(for: input.kind),
                modifiedAt: now
            )
        }

        let expectedSnapshot = try snapshot()
        let valid = try store.writeShadowDryRunParityArtifact(
            runID: runID,
            policyVersion: policyVersion,
            evidenceInputs: inputs,
            artifactDescriptor: artifactDescriptor,
            manifestDescriptor: manifestDescriptor,
            expectedSourceRunSnapshot: expectedSnapshot,
            observedSourceRunSnapshot: expectedSnapshot,
            generatedAt: now.addingTimeInterval(10),
            now: now.addingTimeInterval(10)
        )
        XCTAssertTrue(valid.resultHeld)
        XCTAssertEqual(valid.artifact.state, .valid)
        XCTAssertTrue(valid.artifact.sourceSnapshotBindingHeld)
        XCTAssertFalse(valid.artifact.sourceSnapshotMismatch)
        XCTAssertEqual(valid.artifact.expectedSourceRunSnapshot?.snapshotChecksum, expectedSnapshot.snapshotChecksum)
        XCTAssertEqual(valid.artifact.observedSourceRunSnapshot?.snapshotChecksum, expectedSnapshot.snapshotChecksum)
        XCTAssertFalse(valid.artifact.productionCutoverAuthorized)
        XCTAssertFalse(valid.artifact.productionSecretRead)
        XCTAssertFalse(valid.artifact.productionEndpointConnected)
        XCTAssertFalse(valid.artifact.brokerEndpointConnected)
        XCTAssertFalse(valid.artifact.productionOrderSubmitted)
        XCTAssertFalse(valid.artifact.testnetOrderSubmissionAllowed)

        let output = try String(
            contentsOf: store.artifactURL(for: artifactDescriptor),
            encoding: .utf8
        )
        XCTAssertTrue(output.contains("\"sourceSnapshotBindingHeld\":true"))
        XCTAssertTrue(output.contains(expectedSnapshot.snapshotChecksum))
        XCTAssertTrue(output.contains(checksum("a")))
        XCTAssertTrue(output.contains("event-1"))
        XCTAssertTrue(output.contains("risk-decision-1"))
        XCTAssertTrue(output.contains("oms-dry-run-1"))
        XCTAssertTrue(output.contains(checksum("b")))
        XCTAssertTrue(output.contains(checksum("c")))

        for mutated in [
            try snapshot(manifest: "d"),
            try snapshot(eventIDs: ["event-1", "event-mutated"]),
            try snapshot(riskDecisionIDs: ["risk-decision-mutated"]),
            try snapshot(omsDryRunLifecycleIDs: ["oms-dry-run-mutated"]),
            try snapshot(portfolio: "e"),
            try snapshot(reconciliation: "f")
        ] {
            let invalid = try store.writeShadowDryRunParityArtifact(
                runID: runID,
                policyVersion: policyVersion,
                evidenceInputs: inputs,
                artifactDescriptor: artifactDescriptor,
                manifestDescriptor: manifestDescriptor,
                expectedSourceRunSnapshot: expectedSnapshot,
                observedSourceRunSnapshot: mutated,
                generatedAt: now.addingTimeInterval(20),
                now: now.addingTimeInterval(20)
            )
            XCTAssertTrue(invalid.resultHeld)
            XCTAssertEqual(invalid.artifact.state, .invalid)
            XCTAssertFalse(invalid.artifact.sourceSnapshotBindingHeld)
            XCTAssertTrue(invalid.artifact.sourceSnapshotMismatch)
            XCTAssertTrue(invalid.artifact.invalidEvidenceKinds.isEmpty)
            XCTAssertTrue(invalid.artifact.stateReason.contains("source run snapshot changed"))
            XCTAssertFalse(invalid.artifact.productionCutoverAuthorized)
            XCTAssertFalse(invalid.artifact.productionSecretRead)
            XCTAssertFalse(invalid.artifact.productionEndpointConnected)
            XCTAssertFalse(invalid.artifact.brokerEndpointConnected)
            XCTAssertFalse(invalid.artifact.productionOrderSubmitted)
            XCTAssertFalse(invalid.artifact.testnetOrderSubmissionAllowed)
        }

        let source = try read("Sources/ExecutionClient/FutureGate/ReleaseV0110ProductionReadinessArtifactStore.swift")
        let contract = try read("docs/contracts/release-v0.12.0-readiness-assessment-session-contract.md")
        let verifier = try read("checks/verify-v0.12.0.sh")
        let readiness = try read("docs/automation/automation-readiness.md")
        let readinessScript = try read("checks/automation-readiness.sh")
        let validationPlan = try read("docs/validation/validation-plan.md")
        let tradingMatrix = try read("docs/validation/trading-validation-matrix.md")
        let latest = try read("docs/validation/latest-verification-summary.md")

        for anchor in ReleaseV0120ShadowParitySourceSnapshotAnchors.validationAnchors {
            XCTAssertTrue(source.contains(anchor), "\(anchor) must stay in Swift source")
            XCTAssertTrue(contract.contains(anchor), "\(anchor) must stay in v0.12.0 contract")
            XCTAssertTrue(verifier.contains(anchor), "\(anchor) must stay in v0.12.0 verifier")
            XCTAssertTrue(readiness.contains(anchor), "\(anchor) must stay in automation readiness docs")
            XCTAssertTrue(readinessScript.contains(anchor), "\(anchor) must stay in automation readiness shell gate")
            XCTAssertTrue(validationPlan.contains(anchor), "\(anchor) must stay in validation plan")
            XCTAssertTrue(tradingMatrix.contains(anchor), "\(anchor) must stay in trading validation matrix")
            XCTAssertTrue(latest.contains(anchor), "\(anchor) must stay in latest verification summary")
        }

        for requiredString in [
            "ReleaseV0120ShadowParitySourceRunSnapshot",
            "sourceRunManifestChecksum",
            "eventIDs",
            "riskDecisionIDs",
            "omsDryRunLifecycleIDs",
            "portfolioProjectionChecksum",
            "reconciliationChecksum",
            "sourceSnapshotBindingHeld",
            "sourceSnapshotMismatch",
            "testGH961ShadowParityBindsImmutableSourceRunSnapshot"
        ] {
            XCTAssertTrue(
                source.contains(requiredString)
                    || contract.contains(requiredString)
                    || verifier.contains(requiredString)
                    || readiness.contains(requiredString)
                    || readinessScript.contains(requiredString)
                    || validationPlan.contains(requiredString)
                    || tradingMatrix.contains(requiredString)
                    || latest.contains(requiredString),
                "\(requiredString) must stay wired into GH-961 evidence"
            )
        }

        for forbidden in [
            "productionTradingEnabledByDefault=true",
            "productionCutoverAuthorized=true",
            "productionSecretRead=true",
            "productionEndpointConnected=true",
            "brokerEndpointConnected=true",
            "productionOrderSubmitted=true"
        ] {
            XCTAssertFalse(contract.contains(forbidden), "\(forbidden) must stay out of #961 contract")
            XCTAssertFalse(latest.contains(forbidden), "\(forbidden) must stay out of latest summary")
        }
    }

    func testGH962ReadinessAssessmentDiffCompareIsLocalAndNonMutating() throws {
        // 测试场景：GH-962 为 operator review 生成两个 assessment 的本地 compare report；
        // compare 只能读取本地 snapshot / checksum，不修改 registry，也不授权 production cutover。
        let repositoryRoot = URL(fileURLWithPath: FileManager.default.currentDirectoryPath, isDirectory: true)
        func read(_ relativePath: String) throws -> String {
            try String(contentsOf: repositoryRoot.appendingPathComponent(relativePath), encoding: .utf8)
        }

        let expectedAnchors = [
            "GH-962-VERIFY-V0120-READINESS-ASSESSMENT-DIFF-COMPARE",
            "TVM-RELEASE-V0120-READINESS-ASSESSMENT-DIFF-COMPARE",
            "V0120-011-READINESS-ASSESSMENT-DIFF-COMPARE",
            "V0120-011-POLICY-ARTIFACT-RISK-KILL-APPROVAL-SECTIONS",
            "V0120-011-SOURCE-RUN-EVIDENCE-COMPARISON",
            "V0120-011-NON-MUTATING-COMPARE",
            "V0120-011-NO-PRODUCTION-CUTOVER"
        ]
        for anchor in expectedAnchors {
            XCTAssertTrue(
                ReadinessAssessmentRegistryStoreAnchors.validationAnchors.contains(anchor),
                "\(anchor) must stay in registry store anchors"
            )
        }

        XCTAssertEqual(ReadinessAssessmentComparisonSection.allCases.map(\.rawValue), [
            "policy",
            "artifacts",
            "risk-limits",
            "kill-switch-state",
            "approval-state",
            "source-run-evidence"
        ])
        XCTAssertEqual(ReadinessAssessmentComparisonDeltaState.allCases.map(\.rawValue), ["unchanged", "changed"])

        let root = FileManager.default.temporaryDirectory
            .appendingPathComponent("MTPRO-GH962-ReadinessAssessmentCompare-\(UUID().uuidString)", isDirectory: true)
        addTeardownBlock {
            try? FileManager.default.removeItem(at: root)
        }

        let store = ReadinessAssessmentRegistryStore(storageRootURL: root)
        let createdAt = Date(timeIntervalSince1970: 1_812_900_000)
        let baselineID = Identifier.constant("gh-962-baseline-assessment")
        let followUpID = Identifier.constant("gh-962-follow-up-assessment")
        let baselineGeneration = Identifier.constant("gh-962-generation-1")
        let followUpGeneration = Identifier.constant("gh-962-generation-2")

        _ = try store.create(
            assessmentID: baselineID,
            state: .ready,
            sourceReleaseVersion: "v0.12.0",
            assessedBy: "Codex",
            reason: "baseline assessment ready for local compare",
            createdAt: createdAt,
            updatedAt: createdAt
        )
        _ = try store.create(
            assessmentID: followUpID,
            state: .compareReady,
            sourceReleaseVersion: "v0.12.0",
            comparisonBaseAssessmentID: baselineID,
            assessedBy: "Codex",
            reason: "follow-up assessment ready for local compare",
            createdAt: createdAt,
            updatedAt: createdAt.addingTimeInterval(60)
        )
        let registryBeforeCompare = try store.load()

        func checksum(_ scalar: String) -> String {
            "sha256:" + String(repeating: scalar, count: 64)
        }

        func sourceSnapshot(
            run: String,
            manifest: String,
            events: [String],
            riskDecisions: [String],
            omsLifecycles: [String],
            portfolio: String,
            reconciliation: String
        ) throws -> ReleaseV0120ShadowParitySourceRunSnapshot {
            try ReleaseV0120ShadowParitySourceRunSnapshot(
                runID: Identifier.constant(run),
                sourceRunManifestChecksum: checksum(manifest),
                eventIDs: events.map { Identifier.constant($0) },
                riskDecisionIDs: riskDecisions.map { Identifier.constant($0) },
                omsDryRunLifecycleIDs: omsLifecycles.map { Identifier.constant($0) },
                portfolioProjectionChecksum: checksum(portfolio),
                reconciliationChecksum: checksum(reconciliation)
            )
        }

        let baselineSnapshot = try ReadinessAssessmentComparisonSnapshot(
            assessmentID: baselineID,
            generationID: baselineGeneration,
            policyChecksum: checksum("a"),
            artifactBundleChecksum: checksum("b"),
            riskLimitChecksum: checksum("c"),
            killSwitchStateChecksum: checksum("d"),
            approvalStateChecksum: checksum("e"),
            sourceRunSnapshot: sourceSnapshot(
                run: "gh-962-run-baseline",
                manifest: "f",
                events: ["event-1", "event-2"],
                riskDecisions: ["risk-1"],
                omsLifecycles: ["oms-1"],
                portfolio: "1",
                reconciliation: "2"
            )
        )
        let followUpSnapshot = try ReadinessAssessmentComparisonSnapshot(
            assessmentID: followUpID,
            generationID: followUpGeneration,
            policyChecksum: checksum("a"),
            artifactBundleChecksum: checksum("3"),
            riskLimitChecksum: checksum("c"),
            killSwitchStateChecksum: checksum("4"),
            approvalStateChecksum: checksum("5"),
            sourceRunSnapshot: sourceSnapshot(
                run: "gh-962-run-follow-up",
                manifest: "6",
                events: ["event-1", "event-3"],
                riskDecisions: ["risk-1", "risk-2"],
                omsLifecycles: ["oms-1"],
                portfolio: "7",
                reconciliation: "8"
            )
        )

        let comparedAt = createdAt.addingTimeInterval(120)
        let report = try store.compareAssessments(
            baselineSnapshot: baselineSnapshot,
            followUpSnapshot: followUpSnapshot,
            comparedAt: comparedAt
        )
        XCTAssertTrue(report.reportHeld)
        XCTAssertEqual(report.baselineAssessmentID, baselineID)
        XCTAssertEqual(report.followUpAssessmentID, followUpID)
        XCTAssertEqual(report.baselineGenerationID, baselineGeneration)
        XCTAssertEqual(report.followUpGenerationID, followUpGeneration)
        XCTAssertEqual(report.comparedSections, ReadinessAssessmentComparisonSection.allCases)
        XCTAssertEqual(report.unchangedSections, [.policy, .riskLimits])
        XCTAssertEqual(report.changedSections, [.artifacts, .killSwitchState, .approvalState, .sourceRunEvidence])
        XCTAssertTrue(report.hasDifferences)
        XCTAssertTrue(report.compareDoesNotMutateAssessments)
        XCTAssertTrue(report.operatorReviewOnly)
        XCTAssertEqual(
            report.reportChecksum,
            ReadinessAssessmentComparisonReport.stableReportChecksum(
                baselineAssessmentID: baselineID,
                followUpAssessmentID: followUpID,
                baselineGenerationID: baselineGeneration,
                followUpGenerationID: followUpGeneration,
                comparedAt: comparedAt,
                deltas: report.deltas
            )
        )

        let registryAfterCompare = try store.load()
        XCTAssertEqual(registryAfterCompare, registryBeforeCompare)
        XCTAssertFalse(report.productionTradingEnabledByDefault)
        XCTAssertFalse(report.productionCutoverAuthorized)
        XCTAssertFalse(report.productionSecretRead)
        XCTAssertFalse(report.productionEndpointConnected)
        XCTAssertFalse(report.brokerEndpointConnected)
        XCTAssertFalse(report.productionOrderSubmitted)
        XCTAssertFalse(report.realOrderSubmissionEnabled)
        XCTAssertFalse(report.testnetOrderSubmissionAllowed)
        XCTAssertFalse(report.testnetOrderRoutingAllowed)

        let encodedReport = try XCTUnwrap(String(data: JSONEncoder().encode(report), encoding: .utf8))
        for required in [
            "\"policy\"",
            "\"artifacts\"",
            "\"risk-limits\"",
            "\"kill-switch-state\"",
            "\"approval-state\"",
            "\"source-run-evidence\"",
            "\"compareDoesNotMutateAssessments\":true",
            "\"operatorReviewOnly\":true"
        ] {
            XCTAssertTrue(encodedReport.contains(required), "\(required) must stay in encoded GH-962 compare report")
        }
        for forbidden in [
            "productionTradingEnabledByDefault\":true",
            "productionCutoverAuthorized\":true",
            "productionSecretRead\":true",
            "productionEndpointConnected\":true",
            "brokerEndpointConnected\":true",
            "productionOrderSubmitted\":true",
            "realOrderSubmissionEnabled\":true",
            "testnetOrderSubmissionAllowed\":true",
            "testnetOrderRoutingAllowed\":true"
        ] {
            XCTAssertFalse(encodedReport.contains(forbidden), "\(forbidden) must stay false in GH-962 compare report")
        }

        XCTAssertThrowsError(
            try ReadinessAssessmentComparisonSnapshot(
                assessmentID: Identifier.constant("gh-962-bad-assessment"),
                generationID: Identifier.constant("gh-962-bad-generation"),
                policyChecksum: checksum("a"),
                artifactBundleChecksum: checksum("b"),
                riskLimitChecksum: checksum("c"),
                killSwitchStateChecksum: checksum("d"),
                approvalStateChecksum: checksum("e"),
                sourceRunSnapshot: baselineSnapshot.sourceRunSnapshot,
                productionCutoverAuthorized: true
            )
        ) { error in
            XCTAssertEqual(error as? ReadinessAssessmentRegistryStoreError, .boundaryDrift("readinessAssessmentComparisonSnapshot"))
        }

        let source = try read("Sources/ExecutionClient/FutureGate/ReleaseV0120ReadinessAssessmentRegistryStore.swift")
        let contract = try read("docs/contracts/release-v0.12.0-readiness-assessment-session-contract.md")
        let verifier = try read("checks/verify-v0.12.0.sh")
        let readiness = try read("docs/automation/automation-readiness.md")
        let readinessScript = try read("checks/automation-readiness.sh")
        let validationPlan = try read("docs/validation/validation-plan.md")
        let tradingMatrix = try read("docs/validation/trading-validation-matrix.md")
        let latest = try read("docs/validation/latest-verification-summary.md")

        for anchor in expectedAnchors {
            XCTAssertTrue(source.contains(anchor), "\(anchor) must stay in Swift source")
            XCTAssertTrue(contract.contains(anchor), "\(anchor) must stay in v0.12.0 contract")
            XCTAssertTrue(verifier.contains(anchor), "\(anchor) must stay in v0.12.0 verifier")
            XCTAssertTrue(readiness.contains(anchor), "\(anchor) must stay in automation readiness docs")
            XCTAssertTrue(readinessScript.contains(anchor), "\(anchor) must stay in automation readiness shell gate")
            XCTAssertTrue(validationPlan.contains(anchor), "\(anchor) must stay in validation plan")
            XCTAssertTrue(tradingMatrix.contains(anchor), "\(anchor) must stay in trading validation matrix")
            XCTAssertTrue(latest.contains(anchor), "\(anchor) must stay in latest verification summary")
        }

        for requiredSource in [
            "ReadinessAssessmentComparisonSnapshot",
            "ReadinessAssessmentComparisonReport",
            "ReadinessAssessmentComparisonDelta",
            "compareAssessments",
            "policyChecksum",
            "artifactBundleChecksum",
            "riskLimitChecksum",
            "killSwitchStateChecksum",
            "approvalStateChecksum",
            "sourceRunSnapshot",
            "testGH962ReadinessAssessmentDiffCompareIsLocalAndNonMutating"
        ] {
            XCTAssertTrue(
                source.contains(requiredSource)
                    || verifier.contains(requiredSource)
                    || readinessScript.contains(requiredSource),
                "\(requiredSource) must stay wired into GH-962 source / verifier evidence"
            )
        }
    }

