    func testGH998ReleaseV0130ValidateRejectsBrokenEvidenceChain() throws {
        // 测试场景：GH-998 将 `readiness validate` 从存在性检查升级为完整 evidence-chain
        // consistency check。registry、Manifest V2、Bundle V2、bundle manifest、artifact
