                operatorGate: operatorGate,
                request: request,
                result: result,
                acknowledgement: acknowledgement,
                response: response
            )
            return (intent, request, response, path)
        }

        let submit = try makeSubmitEvidence(
            productType: .spot,
            strategy: .ema,
            side: .buy,
            timeInForce: .goodTillCanceled,
