        XCTAssertEqual(partialFillStream.projection(for: localOrder.localOrderID)?.currentState, OrderLifecycleState.partiallyFilled)

        let cancelRequestStream = try partialFillStream.append(
            omsEvent: cancelRequestedStore.events[2],
            correlationID: correlationID,
            riskEvidenceID: riskEvidenceID,
            executionEvidenceID: Identifier.constant("gh-1032-cancel-request-execution-evidence"),
            adapterEvidenceID: Identifier.constant("gh-1032-testnet-cancel-adapter-evidence")
        )
        XCTAssertTrue(cancelRequestStream.boundaryHeld)
        XCTAssertEqual(cancelRequestStream.events.map { $0.sequence }, [1, 2, 3])
        XCTAssertEqual(cancelRequestStream.events.map { $0.localOrderID }, [localOrder.localOrderID, localOrder.localOrderID, localOrder.localOrderID])
        XCTAssertEqual(cancelRequestStream.projections.count, 1)
        let projection: ReleaseV0140OrderEventSourcingProjection = try XCTUnwrap(cancelRequestStream.projection(for: localOrder.localOrderID))
        XCTAssertTrue(projection.boundaryHeld)
        XCTAssertEqual(projection.currentState, OrderLifecycleState.cancelRequested)
        XCTAssertEqual(projection.eventIDs, cancelRequestStream.events.map { $0.eventID })
        XCTAssertEqual(projection.correlationIDs, [correlationID])
        XCTAssertEqual(projection.causationIDs, cancelRequestStream.events.map { $0.causationID })
        XCTAssertEqual(projection.orderIntentID, submit.intent.intentID)
        XCTAssertEqual(projection.riskEvidenceIDs, [riskEvidenceID])
        XCTAssertEqual(
            projection.executionEvidenceIDs,
            [
                submit.response.responseID,
                Identifier.constant("gh-1032-partial-fill-execution-evidence"),
                Identifier.constant("gh-1032-cancel-request-execution-evidence")
            ]
        )
        XCTAssertEqual(projection.omsEvidenceIDs, cancelRequestedStore.events.map { $0.eventID })
        XCTAssertEqual(
            projection.adapterEvidenceIDs,
            [
                submit.path.pathID,
                Identifier.constant("gh-1032-testnet-cancel-adapter-evidence")
            ]
        )
        XCTAssertFalse(projection.productionTradingEnabledByDefault)
        XCTAssertFalse(projection.productionSecretRead)
        XCTAssertFalse(projection.productionEndpointConnected)

        let replayed = try ReleaseV0140OrderEventSourcingStream.replay(events: cancelRequestStream.events)
        XCTAssertTrue(replayed.boundaryHeld)
        XCTAssertEqual(replayed.events, cancelRequestStream.events)
        XCTAssertEqual(replayed.projections, cancelRequestStream.projections)
        XCTAssertEqual(replayed.nextSequence, cancelRequestStream.nextSequence)

        XCTAssertThrowsError(
            try ReleaseV0140OrderEventSourcingStream.replay(events: Array(cancelRequestStream.events.reversed()))
        )
        XCTAssertThrowsError(
            try emptyStream.append(
                omsEvent: partiallyFilledStore.events[1],
                correlationID: correlationID,
                riskEvidenceID: riskEvidenceID,
                executionEvidenceID: Identifier.constant("gh-1032-missing-append-execution"),
                adapterEvidenceID: Optional<Identifier>.none
            )
        )
        XCTAssertThrowsError(
            try appendedStream.append(
                omsEvent: appendedStore.events[0],
                correlationID: correlationID,
                riskEvidenceID: riskEvidenceID,
                executionEvidenceID: submit.response.responseID,
                adapterEvidenceID: adapterEvidenceID
            )
        )
        XCTAssertThrowsError(
            try ReleaseV0140OrderEventSourcingEvent.fromOMSStoreEvent(
                sequence: 1,
                omsEvent: appendedStore.events[0],
                correlationID: correlationID,
                riskEvidenceID: nil,
                executionEvidenceID: submit.response.responseID,
                adapterEvidenceID: adapterEvidenceID
            )
        )
        XCTAssertThrowsError(try ReleaseV0140OrderEventSourcingStream(rawBrokerPayloadIncluded: true))
        XCTAssertThrowsError(try ReleaseV0140OrderEventSourcingStream(networkOrderActionPerformed: true))
        XCTAssertThrowsError(try ReleaseV0140OrderEventSourcingStream(productionTradingEnabledByDefault: true))

        for anchor in ReleaseV0140OrderEventSourcingStream.requiredValidationAnchors {
            XCTAssertTrue(source.contains(anchor), "\(anchor) must be anchored in source")
            XCTAssertTrue(contract.contains(anchor), "\(anchor) must be documented")
        }
        XCTAssertTrue(verifier.contains("testGH1032ReleaseV0140OrderEventSourcingAppendsAndReplaysCorrelatedLifecycleEvidence"))
        XCTAssertTrue(runScript.contains("bash checks/verify-v0.14.0-order-event-sourcing.sh"))
        for forbidden in [
            "URLSession",
            "URLRequest",
            "CryptoKit",
            "HMAC",
            "API_KEY",
            "SECRET",
            "signature",
            "listenKey",
            "api.binance.com",
            "fapi.binance.com",
            "dapi.binance.com"
        ] {
            XCTAssertFalse(source.contains(forbidden), "\(forbidden) must not be present in GH-1032 source")
        }
    }

    func testGH1033ReleaseV0140OMSStateSyncEngineDerivesCurrentStateFromEvents() throws {
        // 测试场景：GH-1033 从 GH-1032 order event sourcing stream 同步当前本地 OMS state。
        // 验证目的：当前状态只能来自 append-only events 的 replay；空事件、缺失 append、
        // 缺失中间 lifecycle event 和 projection drift 都必须 fail closed。
        let repositoryRoot = URL(fileURLWithPath: FileManager.default.currentDirectoryPath, isDirectory: true)
        func read(_ relativePath: String) throws -> String {
            try String(contentsOf: repositoryRoot.appendingPathComponent(relativePath), encoding: .utf8)
        }

        let source = try read("Sources/ExecutionClient/FutureGate/ReleaseV0140OMSStateSyncEngine.swift")
        let verifier = try read("checks/verify-v0.14.0-oms-state-sync-engine.sh")
        let runScript = try read("checks/run.sh")
        let contract = try read("docs/contracts/release-v0.14.0-oms-state-sync-engine.md")

        let localOrderID: Identifier = .constant("gh-1033-local-order")
        let correlationID: Identifier = .constant("gh-1033-correlation")
        let orderIntentID: Identifier = .constant("gh-1033-order-intent")
        let riskEvidenceID: Identifier = .constant("gh-1033-risk-evidence")
        let symbol = Symbol.constant("BTCUSDT")

        func makeEvent(
            sequence: Int,
            kind: ReleaseV0140OrderEventSourcingEventKind,
            fromState: OrderLifecycleState,
            toState: OrderLifecycleState,
            causationID: Identifier,
            omsEvidenceID: Identifier,
            executionEvidenceID: Identifier?,
            adapterEvidenceID: Identifier?
        ) throws -> ReleaseV0140OrderEventSourcingEvent {
            let eventID = ReleaseV0140OrderEventSourcingEvent.deterministicID(
                sequence: sequence,
                kind: kind,
                localOrderID: localOrderID,
                toState: toState,
                correlationID: correlationID,
                causationID: causationID,
                omsEvidenceID: omsEvidenceID
            )
            return try ReleaseV0140OrderEventSourcingEvent(
                eventID: eventID,
                sequence: sequence,
                kind: kind,
                localOrderID: localOrderID,
                productType: .spot,
                symbol: symbol,
                fromState: fromState,
                toState: toState,
                correlationID: correlationID,
                causationID: causationID,
                orderIntentID: orderIntentID,
                riskEvidenceID: riskEvidenceID,
                executionEvidenceID: executionEvidenceID,
                omsEvidenceID: omsEvidenceID,
                adapterEvidenceID: adapterEvidenceID,
                sourceOMSStoreEventID: omsEvidenceID
            )
        }

        let appendEvent = try makeEvent(
            sequence: 1,
            kind: .orderAppended,
            fromState: .accepted,
            toState: .accepted,
            causationID: .constant("gh-1033-submit-causation"),
            omsEvidenceID: .constant("gh-1033-oms-append"),
            executionEvidenceID: .constant("gh-1033-submit-response"),
            adapterEvidenceID: .constant("gh-1033-submit-adapter")
        )
        let partialFillEvent = try makeEvent(
            sequence: 2,
            kind: .lifecycleChanged,
            fromState: .accepted,
            toState: .partiallyFilled,
            causationID: .constant("gh-1033-partial-fill-causation"),
            omsEvidenceID: .constant("gh-1033-oms-partial-fill"),
            executionEvidenceID: .constant("gh-1033-partial-fill-execution"),
            adapterEvidenceID: Optional<Identifier>.none
        )
        let cancelRequestedEvent = try makeEvent(
            sequence: 3,
            kind: .lifecycleChanged,
            fromState: .partiallyFilled,
            toState: .cancelRequested,
            causationID: .constant("gh-1033-cancel-request-causation"),
            omsEvidenceID: .constant("gh-1033-oms-cancel-request"),
            executionEvidenceID: .constant("gh-1033-cancel-request-execution"),
            adapterEvidenceID: .constant("gh-1033-cancel-request-adapter")
        )
        let stream = try ReleaseV0140OrderEventSourcingStream.replay(
            events: [appendEvent, partialFillEvent, cancelRequestedEvent]
        )
        let engine = try ReleaseV0140OMSStateSyncEngine()
        XCTAssertTrue(engine.boundaryHeld)
        XCTAssertTrue(engine.derivedFromEventsOnly)
        XCTAssertTrue(engine.missingEventsFailClosed)
        XCTAssertFalse(engine.hiddenRuntimeStateMutated)
        XCTAssertFalse(engine.networkOrderActionPerformed)
        XCTAssertFalse(engine.productionTradingEnabledByDefault)

        let snapshot = try engine.sync(stream: stream)
        XCTAssertTrue(snapshot.boundaryHeld)
        XCTAssertEqual(snapshot.sourceStreamID, stream.streamID)
        XCTAssertEqual(snapshot.sourceEventIDs, stream.events.map(\.eventID))
        XCTAssertEqual(snapshot.sourceProjectionCount, stream.projections.count)
        XCTAssertTrue(snapshot.derivedFromEventsOnly)
        XCTAssertTrue(snapshot.replayVerified)
        XCTAssertTrue(snapshot.missingEventsFailClosed)
        XCTAssertFalse(snapshot.hiddenRuntimeStateMutated)
        XCTAssertFalse(snapshot.productionSecretRead)
        XCTAssertFalse(snapshot.productionEndpointConnected)
        XCTAssertEqual(snapshot.records.count, 1)

        let record = try XCTUnwrap(snapshot.record(for: localOrderID))
        XCTAssertTrue(record.boundaryHeld)
        XCTAssertEqual(record.localOrderID, localOrderID)
        XCTAssertEqual(record.productType, .spot)
        XCTAssertEqual(record.symbol, symbol)
        XCTAssertEqual(record.currentState, OrderLifecycleState.cancelRequested)
        XCTAssertEqual(record.lastEventID, cancelRequestedEvent.eventID)
        XCTAssertEqual(record.eventIDs, stream.events.map(\.eventID))
        XCTAssertEqual(record.correlationIDs, [correlationID])
        XCTAssertEqual(record.causationIDs, stream.events.map(\.causationID))
        XCTAssertEqual(record.orderIntentID, orderIntentID)
        XCTAssertEqual(record.riskEvidenceIDs, [riskEvidenceID])
        XCTAssertEqual(
            record.executionEvidenceIDs,
            [
                Identifier.constant("gh-1033-submit-response"),
                Identifier.constant("gh-1033-partial-fill-execution"),
                Identifier.constant("gh-1033-cancel-request-execution")
            ]
        )
        XCTAssertEqual(record.omsEvidenceIDs, stream.events.map(\.omsEvidenceID))
        XCTAssertEqual(
            record.adapterEvidenceIDs,
            [
                Identifier.constant("gh-1033-submit-adapter"),
                Identifier.constant("gh-1033-cancel-request-adapter")
            ]
        )
        XCTAssertTrue(record.derivedFromEventsOnly)
        XCTAssertFalse(record.hiddenRuntimeStateMutated)
        XCTAssertFalse(record.rawBrokerPayloadIncluded)
        XCTAssertFalse(record.brokerFillIncluded)
        XCTAssertFalse(record.reconciliationIncluded)

        let eventOnlySnapshot = try engine.sync(events: stream.events)
        XCTAssertEqual(eventOnlySnapshot, snapshot)

        let driftedStream = try ReleaseV0140OrderEventSourcingStream(
            events: stream.events,
            projections: [try ReleaseV0140OrderEventSourcingProjection(firstEvent: appendEvent)]
        )
        XCTAssertThrowsError(try engine.sync(stream: driftedStream))
        XCTAssertThrowsError(try engine.sync(events: []))
        XCTAssertThrowsError(try engine.sync(events: [partialFillEvent]))
        XCTAssertThrowsError(try engine.sync(events: [appendEvent, cancelRequestedEvent]))
        XCTAssertThrowsError(try ReleaseV0140OMSStateSyncEngine(hiddenRuntimeStateMutated: true))
        XCTAssertThrowsError(try ReleaseV0140OMSStateSyncEngine(networkOrderActionPerformed: true))
        XCTAssertThrowsError(try ReleaseV0140OMSStateSyncRecord(projection: stream.projections[0], hiddenRuntimeStateMutated: true))
        XCTAssertThrowsError(
            try ReleaseV0140OMSStateSyncSnapshot(
                sourceStreamID: stream.streamID,
                records: snapshot.records,
                sourceEventIDs: [],
                sourceProjectionCount: snapshot.sourceProjectionCount
            )
        )
        XCTAssertThrowsError(
            try ReleaseV0140OMSStateSyncSnapshot(
                sourceStreamID: stream.streamID,
                records: snapshot.records,
                sourceEventIDs: snapshot.sourceEventIDs,
                sourceProjectionCount: snapshot.sourceProjectionCount,
                brokerFillIncluded: true
            )
        )

        for anchor in ReleaseV0140OMSStateSyncSnapshot.requiredValidationAnchors {
            XCTAssertTrue(source.contains(anchor), "\(anchor) must be anchored in source")
            XCTAssertTrue(contract.contains(anchor), "\(anchor) must be documented")
        }
        XCTAssertTrue(verifier.contains("testGH1033ReleaseV0140OMSStateSyncEngineDerivesCurrentStateFromEvents"))
        XCTAssertTrue(runScript.contains("bash checks/verify-v0.14.0-oms-state-sync-engine.sh"))
        for forbidden in [
            "URLSession",
            "URLRequest",
            "CryptoKit",
            "HMAC",
            "API_KEY",
            "SECRET",
            "signature",
            "listenKey",
            "api.binance.com",
            "fapi.binance.com",
            "dapi.binance.com"
        ] {
            XCTAssertFalse(source.contains(forbidden), "\(forbidden) must not be present in GH-1033 source")
        }
    }

    func testGH1034ReleaseV0140PreTradeRiskEngineGateBlocksRejectedIntentsBeforeSubmit() throws {
        // 测试场景：GH-1034 为 v0.14.0 OrderIntent 增加 RiskEngine pre-trade gate。
        // 验证目的：accepted intent 才能进入后续 ExecutionEngine / testnet mapping；
        // rejected / blocked intent 必须在 adapter submit 前 fail closed。
        let repositoryRoot = URL(fileURLWithPath: FileManager.default.currentDirectoryPath, isDirectory: true)
        func read(_ relativePath: String) throws -> String {
            try String(contentsOf: repositoryRoot.appendingPathComponent(relativePath), encoding: .utf8)
        }

        let source = try read("Sources/RiskEngine/LiveGate/ReleaseV0140PreTradeRiskEngineGate.swift")
        let verifier = try read("checks/verify-v0.14.0-pretrade-risk-engine-gate.sh")
        let runScript = try read("checks/run.sh")
        let contract = try read("docs/contracts/release-v0.14.0-pretrade-risk-engine-gate.md")

        func makeIntent(
            productType: ProductType = .spot,
            strategy: OrderIntentStrategyKind = .ema,
            quantityValue: Double = 0.05,
            sequence: Int
        ) throws -> OrderIntent {
            let instrument = InstrumentIdentity.binance(
                productType: productType,
                symbol: Symbol.constant("BTCUSDT")
            )
            let quantity = try Quantity(quantityValue, field: "gh1034.quantity")
            let policy = try OrderIntentPolicy(timeInForce: .goodTillCanceled)
            let correlation = try OrderIntentCorrelationMetadata(
                correlationID: .constant("gh-1034-correlation-\(sequence)"),
                strategySignalID: .constant("gh-1034-signal-\(sequence)"),
                sourceMessageID: .constant("gh-1034-message-\(sequence)"),
                strategyRunID: .constant("gh-1034-run-\(sequence)"),
                sourceSequence: sequence
            )
            return try OrderIntent(
                intentID: OrderIntent.deterministicID(
                    instrument: instrument,
                    side: .buy,
                    quantity: quantity,
                    strategy: strategy,
                    policy: policy,
                    correlation: correlation
                ),
                instrument: instrument,
                side: .buy,
                quantity: quantity,
                strategy: strategy,
                policy: policy,
                correlation: correlation,
                createdAt: Date(timeIntervalSince1970: TimeInterval(sequence))
            )
        }

        let acceptedIntent = try makeIntent(sequence: 1034)
        let gate = try ReleaseV0140PreTradeRiskEngineGate.deterministicFixture()
        XCTAssertTrue(gate.boundaryHeld)
        XCTAssertTrue(gate.runsBeforeExecutionEngineSubmit)
        XCTAssertFalse(gate.productionTradingEnabledByDefault)
        XCTAssertFalse(gate.productionSecretRead)
        XCTAssertFalse(gate.productionEndpointConnected)
        XCTAssertFalse(gate.productionSubmitCancelReplace)

        let accepted = try gate.evaluate(intent: acceptedIntent, referencePrice: 1_000)
        XCTAssertTrue(accepted.boundaryHeld)
        XCTAssertEqual(accepted.outcome, .accepted)
        XCTAssertEqual(accepted.rejectReasons, [.none])
        XCTAssertEqual(accepted.nextLifecycleState, .riskAccepted)
        XCTAssertTrue(accepted.forwardsToExecutionEngine)
        XCTAssertTrue(accepted.adapterSubmitEligible)
        XCTAssertFalse(accepted.rejectedIntentReachedAdapterSubmit)

        let acceptedMapping = try ExecutionContractRequestMapping(
            mappingID: ExecutionContractRequestMapping.deterministicID(
                intentID: acceptedIntent.intentID,
                operation: .submit,
                mode: .binanceTestnet,
                lifecycleState: accepted.nextLifecycleState
            ),
            intent: acceptedIntent,
            operation: .submit,
            mode: .binanceTestnet,
            lifecycleState: accepted.nextLifecycleState
        )
        XCTAssertTrue(acceptedMapping.boundaryHeld)
        XCTAssertEqual(acceptedMapping.lifecycleState, .riskAccepted)

        let quantityRejected = try gate.evaluate(
            intent: makeIntent(quantityValue: 2.0, sequence: 1035),
            referencePrice: 1_000
        )
        XCTAssertEqual(quantityRejected.outcome, .rejected)
        XCTAssertEqual(quantityRejected.rejectReasons, [.quantityLimitExceeded])
        XCTAssertFalse(quantityRejected.forwardsToExecutionEngine)
        XCTAssertFalse(quantityRejected.adapterSubmitEligible)
        XCTAssertEqual(quantityRejected.nextLifecycleState, .riskRejected)

        let notionalRejected = try gate.evaluate(intent: acceptedIntent, referencePrice: 2_000_000)
        XCTAssertEqual(notionalRejected.outcome, .rejected)
        XCTAssertEqual(notionalRejected.rejectReasons, [.notionalLimitExceeded])
        XCTAssertFalse(notionalRejected.adapterSubmitEligible)

        let modeBlocked = try gate.evaluate(
            intent: acceptedIntent,
            referencePrice: 1_000,
            explicitTestnetMode: false
        )
        XCTAssertEqual(modeBlocked.outcome, .blocked)
        XCTAssertEqual(modeBlocked.rejectReasons, [.modeGateFailed])
        XCTAssertEqual(modeBlocked.nextLifecycleState, .failedClosed)
        XCTAssertFalse(modeBlocked.adapterSubmitEligible)

        let noTradeBlocked = try gate.evaluate(
            intent: acceptedIntent,
            referencePrice: 1_000,
            noTradeStateActive: true
        )
        XCTAssertEqual(noTradeBlocked.outcome, .blocked)
        XCTAssertEqual(noTradeBlocked.rejectReasons, [.noTradeStateActive])
        XCTAssertFalse(noTradeBlocked.adapterSubmitEligible)

        let killSwitchBlocked = try gate.evaluate(
            intent: acceptedIntent,
            referencePrice: 1_000,
            killSwitchActive: true
        )
        XCTAssertEqual(killSwitchBlocked.outcome, .blocked)
        XCTAssertEqual(killSwitchBlocked.rejectReasons, [.killSwitchActive])
        XCTAssertFalse(killSwitchBlocked.adapterSubmitEligible)

        let spotOnlyGate = try ReleaseV0140PreTradeRiskEngineGate(
            policyProfile: .deterministicFixture(allowedProductTypes: [.spot])
        )
        let productRejected = try spotOnlyGate.evaluate(
            intent: makeIntent(productType: .usdsPerpetual, sequence: 1036),
            referencePrice: 1_000
        )
        XCTAssertEqual(productRejected.outcome, .rejected)
        XCTAssertEqual(productRejected.rejectReasons, [.productNotAllowed])
        XCTAssertFalse(productRejected.adapterSubmitEligible)

        let emaOnlyGate = try ReleaseV0140PreTradeRiskEngineGate(
            policyProfile: .deterministicFixture(allowedStrategies: [.ema])
        )
        let strategyRejected = try emaOnlyGate.evaluate(
            intent: makeIntent(strategy: .rsi, sequence: 1037),
            referencePrice: 1_000
        )
        XCTAssertEqual(strategyRejected.outcome, .rejected)
        XCTAssertEqual(strategyRejected.rejectReasons, [.strategyNotAllowed])
        XCTAssertFalse(strategyRejected.adapterSubmitEligible)

        let productionBlocked = try gate.evaluate(
            intent: acceptedIntent,
            referencePrice: 1_000,
            productionTradingRequested: true
        )
        XCTAssertEqual(productionBlocked.outcome, .blocked)
        XCTAssertEqual(productionBlocked.rejectReasons, [.productionTradingRequested])
        XCTAssertFalse(productionBlocked.adapterSubmitEligible)

        let evidence = try gate.deterministicEvidence(acceptedIntent: acceptedIntent, referencePrice: 1_000)
        XCTAssertTrue(evidence.boundaryHeld)
        XCTAssertEqual(Set(evidence.decisions.map(\.outcome)), Set(ReleaseV0140PreTradeRiskOutcome.allCases))
        XCTAssertTrue(evidence.decisions.filter { $0.outcome != .accepted }.allSatisfy { $0.adapterSubmitEligible == false })
        let encoded = try JSONEncoder().encode(evidence)
        let decoded = try JSONDecoder().decode(ReleaseV0140PreTradeRiskGateEvidence.self, from: encoded)
        XCTAssertEqual(decoded, evidence)

        XCTAssertThrowsError(
            try ReleaseV0140PreTradeRiskPolicyProfile(
                releaseVenueID: .constant("coinbase"),
                maxQuantity: Quantity(1, field: "gh1034.badVenue.quantity"),
                maxSpotNotional: 50_000,
                maxPerpetualNotional: 25_000
            )
        )
        XCTAssertThrowsError(try gate.evaluate(
            intent: acceptedIntent,
            referencePrice: 1_000,
            executionSubmitAlreadyAttempted: true
        ))
        XCTAssertThrowsError(try ReleaseV0140PreTradeRiskEngineGate(
            policyProfile: .deterministicFixture(),
            productionTradingEnabledByDefault: true
        ))
        XCTAssertThrowsError(
            try ReleaseV0140PreTradeRiskDecision(
                decisionID: ReleaseV0140PreTradeRiskDecision.deterministicID(
                    profileID: gate.policyProfile.profileID,
                    intentID: acceptedIntent.intentID,
                    outcome: .rejected,
                    rejectReasons: [.quantityLimitExceeded]
                ),
                profileID: gate.policyProfile.profileID,
                intent: acceptedIntent,
                outcome: .rejected,
                rejectReasons: [.quantityLimitExceeded],
                referencePrice: 1_000,
                notional: 1_000,
                nextLifecycleState: .riskRejected,
                forwardsToExecutionEngine: false,
                adapterSubmitEligible: true
            )
        )
        XCTAssertThrowsError(
            try ReleaseV0140PreTradeRiskDecision(
                decisionID: ReleaseV0140PreTradeRiskDecision.deterministicID(
                    profileID: gate.policyProfile.profileID,
                    intentID: acceptedIntent.intentID,
                    outcome: .blocked,
                    rejectReasons: [.killSwitchActive]
                ),
                profileID: gate.policyProfile.profileID,
                intent: acceptedIntent,
                outcome: .blocked,
                rejectReasons: [.killSwitchActive],
                referencePrice: 1_000,
                notional: 1_000,
                nextLifecycleState: .failedClosed,
                forwardsToExecutionEngine: false,
                adapterSubmitEligible: false,
                rejectedIntentReachedAdapterSubmit: true
            )
        )

        for anchor in ReleaseV0140PreTradeRiskEngineGate.requiredValidationAnchors {
            XCTAssertTrue(source.contains(anchor), "\(anchor) must be anchored in source")
            XCTAssertTrue(contract.contains(anchor), "\(anchor) must be documented")
        }
        XCTAssertTrue(verifier.contains("testGH1034ReleaseV0140PreTradeRiskEngineGateBlocksRejectedIntentsBeforeSubmit"))
        XCTAssertTrue(runScript.contains("bash checks/verify-v0.14.0-pretrade-risk-engine-gate.sh"))
        for forbidden in [
            "URLSession",
            "URLRequest",
            "CryptoKit",
            "HMAC",
            "API_KEY",
            "SECRET",
            "signature",
            "listenKey",
            "api.binance.com",
            "fapi.binance.com",
            "dapi.binance.com"
        ] {
            XCTAssertFalse(source.contains(forbidden), "\(forbidden) must not be present in GH-1034 source")
        }
    }

    func testGH1035ReleaseV0140GlobalKillSwitchBlocksSubmitCancelReplaceAndAudits() throws {
        // 测试场景：GH-1035 为 v0.14.0 closed loop 增加全局 kill switch。
        // 验证目的：kill switch / no-trade active 时 submit、cancel、replace 必须在
