            let correlation = try OrderIntentCorrelationMetadata(
                correlationID: .constant("gh-1035-correlation-\(sequence)"),
                strategySignalID: .constant("gh-1035-signal-\(sequence)"),
                sourceMessageID: .constant("gh-1035-message-\(sequence)"),
