        }

        let intent = try makeIntent(sequence: 1035)
        let preTradeGate = try ReleaseV0140PreTradeRiskEngineGate.deterministicFixture()
        let acceptedRisk = try preTradeGate.evaluate(intent: intent, referencePrice: 1_000)
        XCTAssertEqual(acceptedRisk.outcome, .accepted)
        XCTAssertTrue(acceptedRisk.adapterSubmitEligible)

        let localOrderID = Identifier.constant(
            "gh-1035-local-oms-order",
            field: "releaseV0140GlobalKillSwitch.localOrderID"
        )
        let activeGate = try ReleaseV0140GlobalKillSwitch.deterministicFixture()
        XCTAssertTrue(activeGate.boundaryHeld)
        XCTAssertTrue(activeGate.policy.killSwitchActive)

        let blockedSubmit = try activeGate.evaluateSubmit(riskDecision: acceptedRisk)
        XCTAssertEqual(blockedSubmit.command, .submit)
        XCTAssertEqual(blockedSubmit.outcome, .blocked)
        XCTAssertEqual(blockedSubmit.blockReasons, [.killSwitchActive])
        XCTAssertFalse(blockedSubmit.requestMappingAllowed)
        XCTAssertFalse(blockedSubmit.adapterActionAllowed)
        XCTAssertTrue(blockedSubmit.auditEvidenceEmitted)
        XCTAssertEqual(blockedSubmit.nextLifecycleState, .failedClosed)
        XCTAssertNil(blockedSubmit.localOrderID)

        let blockedCancel = try activeGate.evaluateCancelOrReplace(
            command: .cancel,
            intentID: acceptedRisk.intentID,
            strategyRunID: acceptedRisk.strategyRunID,
            sourceSequence: acceptedRisk.sourceSequence + 1,
            localOrderID: localOrderID,
            currentLifecycleState: .accepted
        )
        XCTAssertEqual(blockedCancel.command, .cancel)
        XCTAssertEqual(blockedCancel.blockReasons, [.killSwitchActive])
        XCTAssertFalse(blockedCancel.requestMappingAllowed)
        XCTAssertFalse(blockedCancel.adapterActionAllowed)
        XCTAssertEqual(blockedCancel.localOrderID, localOrderID)

        let blockedReplace = try activeGate.evaluateCancelOrReplace(
            command: .replace,
            intentID: acceptedRisk.intentID,
            strategyRunID: acceptedRisk.strategyRunID,
            sourceSequence: acceptedRisk.sourceSequence + 2,
            localOrderID: localOrderID,
            currentLifecycleState: .accepted
        )
        XCTAssertEqual(blockedReplace.command, .replace)
        XCTAssertEqual(blockedReplace.blockReasons, [.killSwitchActive])
        XCTAssertFalse(blockedReplace.requestMappingAllowed)
        XCTAssertFalse(blockedReplace.adapterActionAllowed)

        let missingIdentityCancel = try activeGate.evaluateCancelOrReplace(
            command: .cancel,
            intentID: acceptedRisk.intentID,
            strategyRunID: acceptedRisk.strategyRunID,
            sourceSequence: acceptedRisk.sourceSequence + 3,
            localOrderID: nil,
            currentLifecycleState: .accepted
        )
        XCTAssertEqual(missingIdentityCancel.outcome, .blocked)
        XCTAssertTrue(missingIdentityCancel.blockReasons.contains(.killSwitchActive))
        XCTAssertTrue(missingIdentityCancel.blockReasons.contains(.missingLocalOMSOrderIdentity))
        XCTAssertFalse(missingIdentityCancel.adapterActionAllowed)

        let noTradeGate = try ReleaseV0140GlobalKillSwitch(
            policy: .deterministicFixture(killSwitchActive: false, noTradeStateActive: true)
        )
        let noTradeBlockedSubmit = try noTradeGate.evaluateSubmit(riskDecision: acceptedRisk)
        XCTAssertEqual(noTradeBlockedSubmit.outcome, .blocked)
        XCTAssertEqual(noTradeBlockedSubmit.blockReasons, [.noTradeStateActive])
        XCTAssertFalse(noTradeBlockedSubmit.adapterActionAllowed)

        let inactiveGate = try ReleaseV0140GlobalKillSwitch(
            policy: .deterministicFixture(killSwitchActive: false, noTradeStateActive: false)
        )
        let allowedSubmit = try inactiveGate.evaluateSubmit(riskDecision: acceptedRisk)
        XCTAssertEqual(allowedSubmit.outcome, .allowed)
        XCTAssertEqual(allowedSubmit.blockReasons, [.none])
        XCTAssertTrue(allowedSubmit.requestMappingAllowed)
        XCTAssertTrue(allowedSubmit.adapterActionAllowed)
        XCTAssertEqual(allowedSubmit.nextLifecycleState, .riskAccepted)

        let allowedCancel = try inactiveGate.evaluateCancelOrReplace(
            command: .cancel,
            intentID: acceptedRisk.intentID,
            strategyRunID: acceptedRisk.strategyRunID,
            sourceSequence: acceptedRisk.sourceSequence + 4,
            localOrderID: localOrderID,
            currentLifecycleState: .accepted
        )
        XCTAssertEqual(allowedCancel.outcome, .allowed)
        XCTAssertEqual(allowedCancel.blockReasons, [.none])
        XCTAssertTrue(allowedCancel.requestMappingAllowed)
        XCTAssertTrue(allowedCancel.adapterActionAllowed)

        let rejectedRisk = try preTradeGate.evaluate(
            intent: makeIntent(quantityValue: 2.0, sequence: 1036),
            referencePrice: 1_000
        )
        XCTAssertEqual(rejectedRisk.outcome, .rejected)
        let missingRiskBlocked = try inactiveGate.evaluateSubmit(riskDecision: rejectedRisk)
        XCTAssertEqual(missingRiskBlocked.outcome, .blocked)
        XCTAssertEqual(missingRiskBlocked.blockReasons, [.missingRiskAcceptedDecision])
        XCTAssertFalse(missingRiskBlocked.adapterActionAllowed)

        let evidence = try activeGate.deterministicEvidence(
            riskDecision: acceptedRisk,
            localOrderID: localOrderID
        )
        XCTAssertTrue(evidence.boundaryHeld)
        XCTAssertEqual(Set(evidence.decisions.map(\.command)), Set(ReleaseV0140GlobalKillSwitchCommandKind.allCases))
        XCTAssertTrue(evidence.decisions.allSatisfy { $0.outcome == .blocked })
        XCTAssertTrue(evidence.decisions.allSatisfy(\.auditEvidenceEmitted))
        XCTAssertTrue(evidence.decisions.allSatisfy { $0.requestMappingAllowed == false && $0.adapterActionAllowed == false })
        let encoded = try JSONEncoder().encode(evidence)
        let decoded = try JSONDecoder().decode(ReleaseV0140GlobalKillSwitchEvidence.self, from: encoded)
        XCTAssertEqual(decoded, evidence)

        XCTAssertThrowsError(try ReleaseV0140GlobalKillSwitchPolicy(coveredCommands: [.submit]))
        XCTAssertThrowsError(try ReleaseV0140GlobalKillSwitchPolicy(productionTradingEnabledByDefault: true))
        XCTAssertThrowsError(try ReleaseV0140GlobalKillSwitchPolicy(productionSecretRead: true))
        XCTAssertThrowsError(try ReleaseV0140GlobalKillSwitchPolicy(productionEndpointConnected: true))
        XCTAssertThrowsError(try ReleaseV0140GlobalKillSwitchPolicy(productionSubmitCancelReplace: true))
        XCTAssertThrowsError(try activeGate.evaluateCancelOrReplace(
            command: .submit,
            intentID: acceptedRisk.intentID,
            strategyRunID: acceptedRisk.strategyRunID,
            sourceSequence: acceptedRisk.sourceSequence + 5,
            localOrderID: localOrderID,
            currentLifecycleState: .accepted
        ))
        XCTAssertThrowsError(
            try ReleaseV0140GlobalKillSwitchDecision(
                decisionID: ReleaseV0140GlobalKillSwitchDecision.deterministicID(
                    policyID: activeGate.policy.policyID,
                    command: .submit,
                    intentID: acceptedRisk.intentID,
                    sourceSequence: acceptedRisk.sourceSequence + 6,
                    outcome: .blocked
                ),
                policyID: activeGate.policy.policyID,
                command: .submit,
                intentID: acceptedRisk.intentID,
                strategyRunID: acceptedRisk.strategyRunID,
                sourceSequence: acceptedRisk.sourceSequence + 6,
                localOrderID: nil,
                inputLifecycleState: .riskAccepted,
                outcome: .blocked,
                blockReasons: [.killSwitchActive],
                requestMappingAllowed: true,
                adapterActionAllowed: false,
                nextLifecycleState: .failedClosed
            )
        )
        XCTAssertThrowsError(
            try ReleaseV0140GlobalKillSwitchDecision(
                decisionID: ReleaseV0140GlobalKillSwitchDecision.deterministicID(
                    policyID: activeGate.policy.policyID,
                    command: .replace,
                    intentID: acceptedRisk.intentID,
                    sourceSequence: acceptedRisk.sourceSequence + 7,
                    outcome: .allowed
                ),
                policyID: activeGate.policy.policyID,
                command: .replace,
                intentID: acceptedRisk.intentID,
                strategyRunID: acceptedRisk.strategyRunID,
                sourceSequence: acceptedRisk.sourceSequence + 7,
                localOrderID: nil,
                inputLifecycleState: .accepted,
                outcome: .allowed,
                blockReasons: [.none],
                requestMappingAllowed: true,
                adapterActionAllowed: true,
                nextLifecycleState: .accepted
            )
        )
        XCTAssertThrowsError(
            try ReleaseV0140GlobalKillSwitchEvidence(
                evidenceID: ReleaseV0140GlobalKillSwitchEvidence.deterministicID(
                    policyID: activeGate.policy.policyID,
                    decisions: [blockedSubmit, blockedCancel]
                ),
                policyID: activeGate.policy.policyID,
                decisions: [blockedSubmit, blockedCancel]
            )
        )

        for anchor in ReleaseV0140GlobalKillSwitch.requiredValidationAnchors {
            XCTAssertTrue(source.contains(anchor), "\(anchor) must be anchored in source")
            XCTAssertTrue(contract.contains(anchor), "\(anchor) must be documented")
        }
        XCTAssertTrue(verifier.contains("testGH1035ReleaseV0140GlobalKillSwitchBlocksSubmitCancelReplaceAndAudits"))
        XCTAssertTrue(runScript.contains("bash checks/verify-v0.14.0-global-kill-switch.sh"))
        for forbidden in [
            "URLSession",
            "URLRequest",
            "CryptoKit",
            "HMAC",
            "API_KEY",
            "SECRET",
            "signature",
            "listenKey",
            "api.binance.com",
            "fapi.binance.com",
            "dapi.binance.com"
        ] {
            XCTAssertFalse(source.contains(forbidden), "\(forbidden) must not be present in GH-1035 source")
        }
    }

    func testGH1036ReleaseV0140ReconciliationEngineSurfacesMismatchesAsFailures() throws {
        // 测试场景：GH-1036 对齐本地 OMS state sync、append-only event log 和 testnet ack / fill evidence。
        // 验证目的：一致 evidence 生成 passed report；状态或 coverage mismatch 必须进入 failed report，
        // 不能被 reconciliation 静默接受。
        let repositoryRoot = URL(fileURLWithPath: FileManager.default.currentDirectoryPath, isDirectory: true)
        func read(_ relativePath: String) throws -> String {
            try String(contentsOf: repositoryRoot.appendingPathComponent(relativePath), encoding: .utf8)
        }

        let source = try read("Sources/ExecutionClient/FutureGate/ReleaseV0140ReconciliationEngine.swift")
        let verifier = try read("checks/verify-v0.14.0-reconciliation-engine.sh")
        let runScript = try read("checks/run.sh")
        let contract = try read("docs/contracts/release-v0.14.0-reconciliation-engine.md")

        let localOrderID: Identifier = .constant("gh-1036-local-order")
        let correlationID: Identifier = .constant("gh-1036-correlation")
        let orderIntentID: Identifier = .constant("gh-1036-order-intent")
        let riskEvidenceID: Identifier = .constant("gh-1036-risk-evidence")
        let symbol = Symbol.constant("BTCUSDT")

        func makeEvent(
            sequence: Int,
            kind: ReleaseV0140OrderEventSourcingEventKind,
            fromState: OrderLifecycleState,
            toState: OrderLifecycleState,
            causationID: Identifier,
            omsEvidenceID: Identifier,
            executionEvidenceID: Identifier?,
            adapterEvidenceID: Identifier?
        ) throws -> ReleaseV0140OrderEventSourcingEvent {
            let eventID = ReleaseV0140OrderEventSourcingEvent.deterministicID(
                sequence: sequence,
                kind: kind,
                localOrderID: localOrderID,
                toState: toState,
                correlationID: correlationID,
                causationID: causationID,
                omsEvidenceID: omsEvidenceID
            )
            return try ReleaseV0140OrderEventSourcingEvent(
                eventID: eventID,
                sequence: sequence,
                kind: kind,
                localOrderID: localOrderID,
                productType: .spot,
                symbol: symbol,
                fromState: fromState,
                toState: toState,
                correlationID: correlationID,
                causationID: causationID,
                orderIntentID: orderIntentID,
                riskEvidenceID: riskEvidenceID,
                executionEvidenceID: executionEvidenceID,
                omsEvidenceID: omsEvidenceID,
                adapterEvidenceID: adapterEvidenceID,
                sourceOMSStoreEventID: omsEvidenceID
            )
        }

        func makeObservation(
            kind: ReleaseV0140ReconciliationObservationKind,
            event: ReleaseV0140OrderEventSourcingEvent,
            targetState: OrderLifecycleState? = nil
        ) throws -> ReleaseV0140TestnetExecutionObservation {
            let executionEvidenceID = try XCTUnwrap(event.executionEvidenceID)
            let resolvedTargetState = targetState ?? event.toState
            return try ReleaseV0140TestnetExecutionObservation(
                observationID: ReleaseV0140TestnetExecutionObservation.deterministicID(
                    kind: kind,
                    localOrderID: event.localOrderID,
                    sourceEventID: event.eventID,
                    executionEvidenceID: executionEvidenceID
                ),
                kind: kind,
                localOrderID: event.localOrderID,
                productType: event.productType,
                symbol: event.symbol,
                orderIntentID: event.orderIntentID,
                sourceEventID: event.eventID,
                targetLifecycleState: resolvedTargetState,
                executionEvidenceID: executionEvidenceID,
                adapterEvidenceID: event.adapterEvidenceID
            )
        }

        let acceptedEvent = try makeEvent(
            sequence: 1,
            kind: .orderAppended,
            fromState: .accepted,
            toState: .accepted,
            causationID: .constant("gh-1036-submit-causation"),
            omsEvidenceID: .constant("gh-1036-oms-accepted"),
            executionEvidenceID: .constant("gh-1036-submit-response"),
            adapterEvidenceID: .constant("gh-1036-submit-adapter")
        )
        let partialFillEvent = try makeEvent(
            sequence: 2,
            kind: .lifecycleChanged,
            fromState: .accepted,
            toState: .partiallyFilled,
            causationID: .constant("gh-1036-partial-fill-causation"),
            omsEvidenceID: .constant("gh-1036-oms-partial-fill"),
            executionEvidenceID: .constant("gh-1036-partial-fill-execution"),
            adapterEvidenceID: nil
        )
        let cancelRequestedEvent = try makeEvent(
            sequence: 3,
            kind: .lifecycleChanged,
            fromState: .partiallyFilled,
            toState: .cancelRequested,
            causationID: .constant("gh-1036-cancel-request-causation"),
            omsEvidenceID: .constant("gh-1036-oms-cancel-request"),
            executionEvidenceID: .constant("gh-1036-cancel-request-execution"),
            adapterEvidenceID: .constant("gh-1036-cancel-request-adapter")
        )
        let cancelledEvent = try makeEvent(
            sequence: 4,
            kind: .lifecycleChanged,
            fromState: .cancelRequested,
            toState: .cancelled,
            causationID: .constant("gh-1036-cancel-ack-causation"),
            omsEvidenceID: .constant("gh-1036-oms-cancelled"),
            executionEvidenceID: .constant("gh-1036-cancel-ack-execution"),
            adapterEvidenceID: .constant("gh-1036-cancel-ack-adapter")
        )

        let stream = try ReleaseV0140OrderEventSourcingStream.replay(
            events: [acceptedEvent, partialFillEvent, cancelRequestedEvent, cancelledEvent]
        )
        let stateSync = try ReleaseV0140OMSStateSyncEngine()
        let snapshot = try stateSync.sync(stream: stream)
        let engine = try ReleaseV0140ReconciliationEngine()
        XCTAssertTrue(engine.boundaryHeld)
        XCTAssertTrue(engine.mismatchesFailClosed)
        XCTAssertTrue(engine.testnetDryRunScoped)
        XCTAssertFalse(engine.networkOrderActionPerformed)
        XCTAssertFalse(engine.productionTradingEnabledByDefault)

        let submitObservation = try makeObservation(kind: .submitAcknowledgement, event: acceptedEvent)
        let partialFillObservation = try makeObservation(kind: .partialFill, event: partialFillEvent)
        let cancelObservation = try makeObservation(kind: .cancelAcknowledgement, event: cancelledEvent)
        let passedReport = try engine.reconcile(
            snapshot: snapshot,
            stream: stream,
            observations: [submitObservation, partialFillObservation, cancelObservation]
        )
        XCTAssertTrue(passedReport.boundaryHeld)
        XCTAssertEqual(passedReport.status, .passed)
        XCTAssertTrue(passedReport.failures.isEmpty)
        XCTAssertTrue(passedReport.evidenceCoverageComplete)
        XCTAssertEqual(passedReport.sourceSnapshotID, snapshot.snapshotID)
        XCTAssertEqual(passedReport.sourceEventIDs, stream.events.map(\.eventID))
        XCTAssertEqual(
            passedReport.observationIDs,
            [submitObservation.observationID, partialFillObservation.observationID, cancelObservation.observationID]
        )

        let mismatchedFillObservation = try makeObservation(
            kind: .fullFill,
            event: partialFillEvent,
            targetState: .filled
        )
        let failedStateReport = try engine.reconcile(
            snapshot: snapshot,
            stream: stream,
            observations: [submitObservation, mismatchedFillObservation, cancelObservation]
        )
        XCTAssertEqual(failedStateReport.status, .failed)
        XCTAssertFalse(failedStateReport.evidenceCoverageComplete)
        XCTAssertTrue(failedStateReport.mismatchesFailClosed)
        XCTAssertTrue(failedStateReport.failures.contains { $0.reason == .lifecycleStateMismatch })
        XCTAssertTrue(failedStateReport.failures.allSatisfy(\.failClosed))

        let failedCoverageReport = try engine.reconcile(
            snapshot: snapshot,
            stream: stream,
            observations: [submitObservation, partialFillObservation]
        )
        XCTAssertEqual(failedCoverageReport.status, .failed)
        XCTAssertTrue(failedCoverageReport.failures.contains { $0.reason == .observationCoverageMismatch })

        XCTAssertThrowsError(try ReleaseV0140ReconciliationEngine(networkOrderActionPerformed: true))
        XCTAssertThrowsError(try ReleaseV0140ReconciliationEngine(productionTradingEnabledByDefault: true))
        XCTAssertThrowsError(try ReleaseV0140TestnetExecutionObservation(
            observationID: ReleaseV0140TestnetExecutionObservation.deterministicID(
                kind: .submitAcknowledgement,
                localOrderID: acceptedEvent.localOrderID,
                sourceEventID: acceptedEvent.eventID,
                executionEvidenceID: try XCTUnwrap(acceptedEvent.executionEvidenceID)
            ),
            kind: .submitAcknowledgement,
            localOrderID: acceptedEvent.localOrderID,
            productType: acceptedEvent.productType,
            symbol: acceptedEvent.symbol,
            orderIntentID: acceptedEvent.orderIntentID,
            sourceEventID: acceptedEvent.eventID,
            targetLifecycleState: .accepted,
            executionEvidenceID: try XCTUnwrap(acceptedEvent.executionEvidenceID),
            adapterEvidenceID: acceptedEvent.adapterEvidenceID,
            rawExecutionPayloadIncluded: true
        ))

        for anchor in ReleaseV0140ReconciliationReport.requiredValidationAnchors {
            XCTAssertTrue(source.contains(anchor), "\(anchor) must be anchored in source")
            XCTAssertTrue(contract.contains(anchor), "\(anchor) must be documented")
        }
        XCTAssertTrue(verifier.contains("testGH1036ReleaseV0140ReconciliationEngineSurfacesMismatchesAsFailures"))
        XCTAssertTrue(runScript.contains("bash checks/verify-v0.14.0-reconciliation-engine.sh"))
        for forbidden in [
            "URLSession",
            "URLRequest",
            "CryptoKit",
            "HMAC",
            "API_KEY",
            "SECRET",
            "signature",
            "listenKey",
            "api.binance.com",
            "fapi.binance.com",
            "dapi.binance.com"
        ] {
            XCTAssertFalse(source.contains(forbidden), "\(forbidden) must not be present in GH-1036 source")
        }
    }

    func testGH1037ReleaseV0140SignalToExecutionPipelineLinksAcceptedSignalAndFailsClosedRejectedSignal() throws {
        // 测试场景：GH-1037 串联 Strategy Signal -> OrderIntent -> RiskEngine -> ExecutionContract
        // -> Binance testnet evidence -> OMS event log -> state sync -> reconciliation。
        // 验证目的：accepted signal 形成完整本地证据链；kill switch / no-trade 等 blocked signal
        // 必须停在 RiskEngine，不能触达 adapter、OMS 或 reconciliation。
        let repositoryRoot = URL(fileURLWithPath: FileManager.default.currentDirectoryPath, isDirectory: true)
        func read(_ relativePath: String) throws -> String {
            try String(contentsOf: repositoryRoot.appendingPathComponent(relativePath), encoding: .utf8)
        }

        let source = try read("Sources/ExecutionEngine/OMSFutureGate/ReleaseV0140SignalToExecutionPipeline.swift")
        let contract = try read("docs/contracts/release-v0.14.0-signal-to-execution-pipeline.md")
        let verifier = try read("checks/verify-v0.14.0-signal-to-execution-pipeline.sh")
        let runScript = try read("checks/run.sh")
        let strategyRegistry = try read("Sources/Trader/Strategies/StrategyRegistry.swift")

        let instrument = InstrumentIdentity.binance(
            productType: .spot,
            symbol: Symbol.constant("BTCUSDT")
        )
        let productAwareIntent = try ProductAwareOrderIntent(
            intentID: .constant("gh-1037-product-aware-ema"),
            instrument: instrument,
            targetExposure: .targetLong,
            quantity: Quantity(0.025, field: "gh1037.quantity"),
            referencePrice: Price(1_000, field: "gh1037.referencePrice"),
            createdAt: Date(timeIntervalSince1970: 1_037)
        )
        let signal = try ReleaseV0140StrategySignalEnvelope(
            signalID: ReleaseV0140StrategySignalEnvelope.deterministicID(
                productAwareIntentID: productAwareIntent.intentID,
                strategy: .ema,
                sourceMessageID: .constant("gh-1037-message"),
                strategyRunID: .constant("gh-1037-run"),
                sourceSequence: 1_037
            ),
            productAwareOrderIntent: productAwareIntent,
            strategy: .ema,
            sourceMessageID: .constant("gh-1037-message"),
            strategyRunID: .constant("gh-1037-run"),
            sourceSequence: 1_037,
            emittedAt: Date(timeIntervalSince1970: 1_037)
        )
        let pipeline = try ReleaseV0140SignalToExecutionPipeline()
        let accepted = try pipeline.run(
            signal: signal,
            referencePrice: 1_000,
            riskGate: .deterministicFixture()
        )

        XCTAssertTrue(signal.boundaryHeld)
        XCTAssertTrue(pipeline.boundaryHeld)
        XCTAssertTrue(accepted.boundaryHeld)
        XCTAssertEqual(accepted.status, .passed)
        XCTAssertEqual(accepted.completedStages, ReleaseV0140SignalToExecutionPipelineReport.requiredPassedStages)
        XCTAssertEqual(accepted.riskOutcome, .accepted)
        XCTAssertNotNil(accepted.executionMappingID)
        XCTAssertNotNil(accepted.submitPathID)
        XCTAssertNotNil(accepted.localOrderID)
        XCTAssertNotNil(accepted.eventStreamID)
        XCTAssertNotNil(accepted.stateSnapshotID)
        XCTAssertNotNil(accepted.reconciliationReportID)
        XCTAssertEqual(accepted.reconciliationStatus, .passed)
        XCTAssertTrue(accepted.testnetSubmitEvidenceCreated)
        XCTAssertTrue(accepted.adapterSubmitEvidenceCreated)
        XCTAssertFalse(accepted.networkSubmitAttempted)
        XCTAssertFalse(accepted.networkCancelReplaceAttempted)
        XCTAssertTrue(accepted.omsEventLogCreated)
        XCTAssertTrue(accepted.reconciliationCompleted)
        XCTAssertTrue(accepted.strategiesNeverCallExecutionClient)
        XCTAssertFalse(accepted.productionTradingEnabledByDefault)
        XCTAssertFalse(accepted.productionSecretRead)
        XCTAssertFalse(accepted.productionEndpointConnected)
        XCTAssertFalse(accepted.productionSubmitCancelReplace)

        let blocked = try pipeline.run(
            signal: signal,
            referencePrice: 1_000,
            riskGate: .deterministicFixture(),
            killSwitchActive: true
        )
        XCTAssertTrue(blocked.boundaryHeld)
        XCTAssertEqual(blocked.status, .failedClosed)
        XCTAssertEqual(blocked.completedStages, ReleaseV0140SignalToExecutionPipelineReport.requiredFailedClosedStages)
        XCTAssertEqual(blocked.riskOutcome, .blocked)
        XCTAssertNil(blocked.executionMappingID)
        XCTAssertNil(blocked.submitPathID)
        XCTAssertNil(blocked.localOrderID)
        XCTAssertNil(blocked.eventStreamID)
        XCTAssertNil(blocked.stateSnapshotID)
        XCTAssertNil(blocked.reconciliationReportID)
        XCTAssertNil(blocked.reconciliationStatus)
        XCTAssertFalse(blocked.testnetSubmitEvidenceCreated)
        XCTAssertFalse(blocked.adapterSubmitEvidenceCreated)
        XCTAssertFalse(blocked.networkSubmitAttempted)
        XCTAssertFalse(blocked.networkCancelReplaceAttempted)
        XCTAssertFalse(blocked.omsEventLogCreated)
        XCTAssertFalse(blocked.reconciliationCompleted)

        let encoded = try JSONEncoder().encode(accepted)
        let decoded = try JSONDecoder().decode(ReleaseV0140SignalToExecutionPipelineReport.self, from: encoded)
        XCTAssertEqual(decoded, accepted)

        XCTAssertThrowsError(
            try ReleaseV0140StrategySignalEnvelope(
                signalID: ReleaseV0140StrategySignalEnvelope.deterministicID(
                    productAwareIntentID: productAwareIntent.intentID,
                    strategy: .ema,
                    sourceMessageID: .constant("gh-1037-direct-message"),
                    strategyRunID: .constant("gh-1037-direct-run"),
                    sourceSequence: 1_038
                ),
                productAwareOrderIntent: productAwareIntent,
                strategy: .ema,
                sourceMessageID: .constant("gh-1037-direct-message"),
                strategyRunID: .constant("gh-1037-direct-run"),
                sourceSequence: 1_038,
                emittedAt: Date(timeIntervalSince1970: 1_038),
                strategyCallsExecutionClient: true
            )
        )
        XCTAssertThrowsError(try ReleaseV0140SignalToExecutionPipeline(productionSubmitCancelReplace: true))

        for anchor in ReleaseV0140SignalToExecutionPipelineReport.requiredValidationAnchors {
            XCTAssertTrue(source.contains(anchor), "\(anchor) must be anchored in source")
            XCTAssertTrue(contract.contains(anchor), "\(anchor) must be documented")
        }
        XCTAssertTrue(verifier.contains("testGH1037ReleaseV0140SignalToExecutionPipelineLinksAcceptedSignalAndFailsClosedRejectedSignal"))
        XCTAssertTrue(runScript.contains("bash checks/verify-v0.14.0-signal-to-execution-pipeline.sh"))
        XCTAssertFalse(strategyRegistry.contains("import ExecutionClient"))
        XCTAssertFalse(strategyRegistry.contains("ExecutionClient."))
        XCTAssertTrue(source.contains("adapterSubmitEvidenceCreated"))
        XCTAssertTrue(source.contains("networkSubmitAttempted"))
        XCTAssertTrue(source.contains("networkCancelReplaceAttempted"))
        XCTAssertFalse(source.contains("adapterSubmit" + "Attempted"))
        for forbidden in [
            "URLSession",
            "URLRequest",
            "CryptoKit",
            "HMAC",
            "API_KEY",
            "SECRET",
            "signature",
            "listenKey",
            "api.binance.com",
            "fapi.binance.com",
            "dapi.binance.com"
        ] {
            XCTAssertFalse(source.contains(forbidden), "\(forbidden) must not be present in GH-1037 source")
        }
    }

