        XCTAssertTrue(validationPlan.contains("GH-1094 Release v0.15.1 v0.15.0 Release Fact Sync / Stale Wording Guard"))
        XCTAssertTrue(tradingMatrix.contains("TVM-RELEASE-V0151-V0150-RELEASE-FACT-SYNC"))
