        XCTAssertTrue(runScript.contains("bash checks/verify-v0.15.1-v0150-release-fact-sync.sh"))

        let docsWithPublicationFacts = [
            readme,
            goal,
            blueprint,
            roadmap,
            latest,
            policy,
            notes,
            validationPlan,
            tradingMatrix,
            readiness
        ]

