        let firstAppend = try writer.appendRuntimeEvents(
            runID: runID,
            events: [
                try ReleaseV070RuntimeEventLogEvent(
                    eventID: Identifier.constant("gh-784-event-1"),
                    payloadJSON: #"{"module":"DataEngine","kind":"market-event"}"#
                ),
