        XCTAssertEqual(hold.targetExposure, .hold)
        XCTAssertEqual(spotLong.instrument.productType, .spot)
        XCTAssertEqual(perpLong.instrument.productType, .usdsPerpetual)
        XCTAssertNil(hold.productAwareOrderIntent)

