        let identifier = Identifier.constant(" gh-434-identifier ", field: "gh434Identifier")
        XCTAssertEqual(identifier.rawValue, "gh-434-identifier")
        XCTAssertEqual(FixtureVersion.constant("fixture-v1").rawValue, "fixture-v1")
