        let sourceFiles = try swiftFiles(
            under: repositoryRoot,
            relativeRoots: ["Sources"]
        )
        let forbiddenForceTryValueObjects = [
            "try! Identifier(",
            "try! FixtureVersion(",
            "try! ScenarioID(",
            "try! DatasetVersion(",
            "try! ScenarioReportInputVersion()"
        ]

        let violations = try sourceFiles.flatMap { file -> [String] in
